const SCENARIOS = {

bd_burger: [
  { dispatch_line:"Medic 12, respond to Big Daddy's Burgers, 101 Big Daddy Blvd — 58-year-old male, chest pain, conscious and breathing.", chief_complaint:"Chest pain with diaphoresis", scene_description:"You arrive to find a heavyset male cook sitting on a milk crate behind the counter, clutching his chest. Coworkers report he complained of heartburn for the past hour before turning pale and sweaty. The smell of grease and smoke fills the kitchen.", patient_info:"58-year-old male, PMH: hypertension, hyperlipidemia, smoker x30 years.", vitals:{bp:"162/98",hr:"96",rr:"18",spo2:"96%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Patient describes crushing substernal chest pain radiating to his left arm, rated 8/10, onset 45 minutes ago. Skin is pale, cool, and diaphoretic. Denies nausea, no JVD noted, lung sounds clear bilaterally.", teaching_points:"1. Chest pain with diaphoresis, radiation, and risk factors is a STEMI until proven otherwise — treat aggressively with position of comfort, O2 if SpO2 <94%, and rapid transport. 2. Always obtain a complete cardiac history including last meal, medications, and time of symptom onset — this information directly affects ER treatment decisions." },
  { dispatch_line:"Medic 12, Big Daddy's Burgers — female patient, difficulty breathing, possibly allergic reaction.", chief_complaint:"Allergic reaction, facial swelling, hives", scene_description:"A 24-year-old waitress is in the break room sitting upright in a chair. Her face is visibly swollen around the lips and eyes, and she has raised, red welts across her arms and neck. A coworker says she ate a burger with a new sauce about 15 minutes ago.", patient_info:"24-year-old female, PMH: seasonal allergies, no known food allergies.", vitals:{bp:"98/60",hr:"118",rr:"24",spo2:"94%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Patient has audible stridor, urticaria across neck and arms, and angioedema of the lips and tongue. She is anxious and says her throat feels like it is closing. No previous anaphylaxis history.", teaching_points:"1. Anaphylaxis with airway compromise is a life threat — epinephrine auto-injector (if allowed by protocol), high-flow O2, and immediate transport are your priorities. 2. SpO2 may appear falsely reassuring early in anaphylaxis — assess work of breathing and stridor as your primary airway indicators." },
  { dispatch_line:"Medic 12, respond to Big Daddy's Burgers, 101 Big Daddy Blvd — patron found unresponsive in the restroom.", chief_complaint:"Unresponsive male, possible overdose", scene_description:"A single-stall men's restroom is locked from the inside. Staff used a key to open it and found a male slumped on the floor between the toilet and wall. A small baggie and a used syringe are visible on the floor beside him. He does not respond to voice.", patient_info:"Approximately 30-year-old male, PMH: unknown, track marks on both arms.", vitals:{bp:"88/50",hr:"54",rr:"6",spo2:"82%",gcs:"3",temp:"97.0°F"}, pertinent_findings:"Patient is unresponsive with pinpoint pupils bilaterally. Respirations are slow and shallow. Airway is partially obstructed with snoring respirations. Cyanosis noted at lips and fingertips.", teaching_points:"1. Opioid overdose presents classically with the triad of altered mental status, respiratory depression, and miosis — manage airway first with BVM ventilation before any other intervention. 2. Naloxone (Narcan) via IN route is within EMT-B scope in most states — know your local protocol and administer early in suspected opioid OD." },
  { dispatch_line:"Medic 12, Big Daddy's Burgers — elderly female, fell in the parking lot, possible hip injury.", chief_complaint:"Fall, hip pain, unable to stand", scene_description:"An elderly woman is lying on her back in the parking lot near the entrance. A witness says she stepped off the curb and immediately fell, crying out in pain. She is alert and talking but cannot move her right leg without severe pain.", patient_info:"78-year-old female, PMH: osteoporosis, atrial fibrillation, takes warfarin.", vitals:{bp:"138/84",hr:"88",rr:"16",spo2:"98%",gcs:"15",temp:"98.2°F"}, pertinent_findings:"Right lower extremity is externally rotated and shortened compared to the left. Patient reports 9/10 pain at right hip and groin. Distal CSM intact. She is on a blood thinner and lives alone.", teaching_points:"1. External rotation and shortening of the lower extremity following a ground-level fall in an elderly patient is a hip fracture until proven otherwise — immobilize and transport without attempting to straighten the limb. 2. Anticoagulant use in elderly trauma patients significantly increases internal bleeding risk even from low-mechanism falls — communicate this to the receiving facility." },
],

bd_bbq: [
  { dispatch_line:"Medic 12, respond to Big Daddy's BBQ Pit, 340 Big Daddy Blvd — report of a burn injury to kitchen staff.", chief_complaint:"Partial thickness burns to forearm and hand", scene_description:"The kitchen is hot and smoky. A male cook is standing at a sink running cold water over his right arm. A large pot of boiling liquid was knocked off a burner and splashed onto him. The burns extend from his wrist to mid-forearm with blistering visible.", patient_info:"34-year-old male, PMH: none, no medications.", vitals:{bp:"142/88",hr:"106",rr:"18",spo2:"99%",gcs:"15",temp:"98.8°F"}, pertinent_findings:"Partial thickness burns covering approximately 9% BSA (right forearm and hand) with blistering and moist, red skin. No circumferential involvement. Airway intact, no singed nasal hairs, no hoarse voice. Pain rated 9/10.", teaching_points:"1. Use the Rule of Nines to estimate burn surface area — the arm equals 9% total; partial vs. full thickness affects treatment priority and transport destination. 2. Do NOT apply ice, butter, or home remedies to burns — cool with room-temperature water briefly, then cover with a dry sterile dressing and transport." },
  { dispatch_line:"Medic 12, Big Daddy's BBQ Pit — male customer, altered mental status, diabetic emergency reported by staff.", chief_complaint:"Diabetic emergency, altered mental status", scene_description:"A male customer is slumped in a corner booth. The manager says he came in alone, ate very little, and has been sitting there for 30 minutes getting increasingly confused. He is mumbling incoherently and did not respond normally when staff tried to talk to him.", patient_info:"52-year-old male, PMH: Type 1 diabetes, wears a medical alert bracelet.", vitals:{bp:"118/72",hr:"102",rr:"16",spo2:"98%",gcs:"12",temp:"98.4°F"}, pertinent_findings:"Patient is diaphoretic and pale with confused speech. Blood glucose by glucometer reads 38 mg/dL. No focal neurological deficits noted. Patient is able to swallow when tested. No trauma noted.", teaching_points:"1. A blood glucose below 60 mg/dL with altered mental status confirms hypoglycemia — if the patient can swallow and protect their airway, oral glucose is first-line treatment at the EMT-B level. 2. Always recheck blood glucose 15 minutes after treatment — if the patient does not improve, transport regardless of glucose level." },
  { dispatch_line:"Medic 12, respond to Big Daddy's BBQ Pit — possible propane leak, one patient with chest pain and dizziness.", chief_complaint:"Carbon monoxide exposure, headache and dizziness", scene_description:"Fire department is already on scene controlling a propane leak near the outdoor pit. One employee did not evacuate promptly and was working near the pit for over an hour. He is now sitting outside complaining of a severe headache, dizziness, and nausea. Other employees appear unaffected.", patient_info:"41-year-old male, PMH: none known, non-smoker.", vitals:{bp:"136/82",hr:"98",rr:"20",spo2:"97%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Patient complains of throbbing frontal headache, nausea, and feeling like he might pass out. SpO2 reads 97% on pulse oximeter but this is unreliable in CO exposure. Skin is flushed. No chest pain. No loss of consciousness.", teaching_points:"1. Pulse oximetry CANNOT distinguish between oxyhemoglobin and carboxyhemoglobin — a normal SpO2 does NOT rule out carbon monoxide poisoning; treat based on exposure history. 2. High-flow oxygen via NRB mask at 15 LPM is the primary treatment for CO poisoning at the EMT-B level — apply immediately and maintain throughout transport." },
  { dispatch_line:"Medic 12, Big Daddy's BBQ Pit — female patient seizing near the outdoor seating area.", chief_complaint:"Witnessed generalized tonic-clonic seizure", scene_description:"You arrive to find a female lying on the ground on the patio. Bystanders say she suddenly stiffened and began convulsing about two minutes ago. She is now in a post-ictal state and breathing on her own but is very confused and slow to respond.", patient_info:"29-year-old female, PMH: epilepsy, takes Keppra daily, last dose unknown.", vitals:{bp:"128/76",hr:"108",rr:"14",spo2:"96%",gcs:"10",temp:"98.8°F"}, pertinent_findings:"Patient is post-ictal, confused, and moving all extremities slowly. Airway is open and she is breathing adequately. No incontinence noted by bystanders. Small abrasion to right temple from fall. No medical alert jewelry other than her wallet card.", teaching_points:"1. During a seizure your only job is to protect the airway and prevent injury — never restrain limbs, never place anything in the mouth; position the patient on their side once the seizure ends. 2. A single seizure in a known epileptic who returns to baseline is lower priority than a first-time seizure, prolonged seizure, or one that doesn't resolve — communicate the duration and history to the ER." },
],

bd_chinese: [
  { dispatch_line:"Medic 12, Big Daddy Dragon Palace, 510 Big Daddy Blvd — elderly male, possible stroke, facial droop reported.", chief_complaint:"Sudden facial droop and arm weakness", scene_description:"An elderly male is seated at a table near the back of the restaurant. His wife flagged down staff when she noticed his face looked different mid-meal. He is awake but has obvious facial asymmetry and is having difficulty speaking clearly.", patient_info:"74-year-old male, PMH: hypertension, atrial fibrillation, takes Eliquis.", vitals:{bp:"188/104",hr:"82",rr:"16",spo2:"97%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"FAST exam positive — left facial droop, left arm drift and weakness, slurred speech. Symptoms began approximately 20 minutes ago per wife. Blood glucose 112 mg/dL. No trauma. Patient is on an anticoagulant.", teaching_points:"1. Time is brain — perform the FAST assessment quickly, document the last known well time precisely, and make transport decisions fast; stroke patients need CT imaging and possible intervention within a narrow time window. 2. Never give anything by mouth to a suspected stroke patient — dysphagia (difficulty swallowing) is common and aspiration is a serious risk." },
  { dispatch_line:"Medic 12, Big Daddy Dragon Palace — choking emergency, adult male, partial obstruction.", chief_complaint:"Choking, partial airway obstruction", scene_description:"A male customer is standing near his table making the universal choking sign with both hands at his throat. He is coughing forcefully and is able to make some noise. His wife is panicking beside him. Other diners have cleared the area.", patient_info:"66-year-old male, PMH: dentures, hypertension.", vitals:{bp:"158/96",hr:"112",rr:"forceful cough",spo2:"93%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Patient is coughing vigorously and can speak in short words. SpO2 is 93% and trending down. He says a large piece of meat is stuck. He is standing and cooperative.", teaching_points:"1. A patient with a partial obstruction who is coughing forcefully should be encouraged to keep coughing — do NOT perform abdominal thrusts on a patient who can still cough effectively as this can convert a partial to a complete obstruction. 2. If the obstruction becomes complete — patient can no longer cough, speak, or breathe — immediately begin back blows and abdominal thrusts per AHA guidelines." },
  { dispatch_line:"Medic 12, respond to Big Daddy Dragon Palace — elderly female, unresponsive at table.", chief_complaint:"Unresponsive female, no pulse", scene_description:"Staff called 911 when a female patron slumped forward at her table. A bystander began CPR before your arrival. You enter to find her on the floor between the tables, CPR in progress. The restaurant has an AED on the wall near the hostess stand.", patient_info:"81-year-old female, PMH: unknown, no medical alert.", vitals:{bp:"no pulse",hr:"no pulse",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Patient is pulseless and apneic. Bystander CPR in progress with good compression depth. No obvious trauma. AED is available. Downtime is estimated at 3-4 minutes per staff.", teaching_points:"1. Minimize interruptions to CPR — analyze with AED as quickly as possible, deliver shock if advised, and immediately resume compressions; every second off the chest matters. 2. High-quality CPR means 100-120 compressions per minute, 2-2.4 inches depth, full chest recoil, and minimal pauses — rotate compressors every 2 minutes to maintain quality." },
  { dispatch_line:"Medic 12, Big Daddy Dragon Palace — elderly male, difficulty breathing, possible allergic reaction to shellfish.", chief_complaint:"Difficulty breathing after eating shrimp", scene_description:"An elderly male is seated at the buffet table leaning forward with his hands on his knees in a tripod position. He tells you he ate the shrimp and within minutes started feeling short of breath. His breathing is audibly wheezy and labored.", patient_info:"70-year-old male, PMH: COPD, hypertension, no known shellfish allergy.", vitals:{bp:"148/90",hr:"114",rr:"28",spo2:"90%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Bilateral expiratory wheezing on auscultation. Mild urticaria on the forearms. No angioedema noted. Using accessory muscles. Pursed lip breathing. No JVD. History of COPD complicates picture — both allergic bronchospasm and COPD exacerbation are possible.", teaching_points:"1. Wheezing plus urticaria after food exposure points strongly to anaphylaxis even without classic skin findings — SpO2 of 90% requires high-flow oxygen and rapid transport. 2. When a patient has both COPD and a possible allergic reaction, treat the most life-threatening presentation first — airway and breathing take priority over determining the exact cause." },
],

bd_pizza: [
  { dispatch_line:"Medic 12, Big Daddy's Pizza Palace, 22 Papa Drive — teenage male, injured during an altercation outside.", chief_complaint:"Stab wound to the abdomen", scene_description:"Police are on scene controlling a group of teens. A 17-year-old male is on the ground holding his abdomen. Bystanders say he was stabbed once during a fight. There is blood visible on his shirt and hands. He is awake and talking but appears frightened.", patient_info:"17-year-old male, PMH: none known.", vitals:{bp:"102/68",hr:"128",rr:"22",spo2:"97%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Single puncture wound approximately 2cm to the left lower quadrant. Abdomen is rigid and tender on palpation. No evisceration. Skin is pale and diaphoretic. Tachycardia and borderline hypotension suggest early shock.", teaching_points:"1. Penetrating abdominal trauma with signs of shock (tachycardia, hypotension, diaphoresis) requires immediate transport — do not delay for detailed assessment; cover the wound with a moist sterile dressing and go. 2. Never remove an impaled object in the field — stabilize it in place with bulky dressings to prevent further injury and uncontrolled hemorrhage." },
  { dispatch_line:"Medic 12, respond to Big Daddy's Pizza Palace — high school student, severe asthma attack.", chief_complaint:"Asthma attack, severe difficulty breathing", scene_description:"A teenage girl is sitting on the curb outside the pizza shop. Her friends say she had an asthma attack and her inhaler is empty. She is leaning forward, unable to speak in full sentences, and her breathing is visibly labored with retractions above the collarbone.", patient_info:"16-year-old female, PMH: moderate persistent asthma, uses albuterol and Flovent.", vitals:{bp:"126/78",hr:"122",rr:"32",spo2:"91%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Severe accessory muscle use with supraclavicular retractions. Audible expiratory wheeze. Speaks only 2-3 words per breath. SpO2 91% on room air. Inhaler used 6 times in past hour with no relief. Prolonged expiratory phase.", teaching_points:"1. A patient who cannot speak in full sentences, has SpO2 below 94%, and has failed their own inhaler is in severe bronchospasm — high-flow O2 and assisted ventilation may be needed; do not wait to see if they improve on their own. 2. Assisting ventilations with a BVM in an asthma patient requires slow, gentle breaths to prevent air trapping and barotrauma — if you push too fast you make it worse." },
  { dispatch_line:"Medic 12, Big Daddy's Pizza Palace — child, approximately 8 years old, hit by a vehicle in the parking lot.", chief_complaint:"Pediatric trauma, struck by vehicle", scene_description:"A child is lying in the parking lot near a slow-moving vehicle. The driver says she was backing out slowly and did not see the child. The boy is crying loudly and moving his arms but not his legs. Bystanders are surrounding him.", patient_info:"Approximately 8-year-old male, PMH: unknown.", vitals:{bp:"100/64",hr:"136",rr:"24",spo2:"96%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"Child is alert but crying and confused about the event. Cannot feel or move legs from the waist down. No obvious deformity to head. Abrasions to both arms and forehead. Mechanism and neuro deficit suggest spinal injury.", teaching_points:"1. Any pediatric trauma patient with lower extremity paralysis after a vehicular mechanism must be treated as a spinal injury — apply manual cervical stabilization immediately and maintain it throughout packaging and transport. 2. Children compensate for shock longer than adults and then deteriorate rapidly — a heart rate of 136 in an 8-year-old with trauma warrants aggressive monitoring even if BP appears normal." },
  { dispatch_line:"Medic 12, Big Daddy's Pizza Palace — employee, laceration to the hand from a pizza cutter, bleeding not controlled.", chief_complaint:"Deep laceration, uncontrolled bleeding", scene_description:"A male employee is in the back kitchen with a bloody towel wrapped around his left hand. The towel is soaked through. He slipped while using an industrial pizza cutter and cut across his palm. He appears pale and anxious.", patient_info:"22-year-old male, PMH: none.", vitals:{bp:"112/70",hr:"116",rr:"18",spo2:"98%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Deep laceration approximately 5cm across the palm with active arterial bleeding that is not controlled by direct pressure alone. Two fingers have reduced sensation. Patient reports he cannot move his index and middle fingers normally.", teaching_points:"1. Direct pressure is the first and most important step in hemorrhage control — apply firm, continuous pressure with a sterile dressing; do not remove soaked dressings, add more on top. 2. Decreased sensation and motor function distal to a laceration suggests possible tendon or nerve involvement — document this carefully and report to the ER as it changes the surgical priority." },
],

bd_taco: [
  { dispatch_line:"Medic 12, Big Daddy's Tacos, 600 Papa Drive — intoxicated male, unresponsive on the sidewalk.", chief_complaint:"Unresponsive male, alcohol intoxication", scene_description:"A male is lying on his back on the sidewalk in front of the taco stand. Staff say he was stumbling around and then simply dropped. He smells strongly of alcohol. He does not respond to verbal commands but moans with a sternal rub.", patient_info:"Approximately 40-year-old male, PMH: unknown.", vitals:{bp:"104/62",hr:"58",rr:"8",spo2:"88%",gcs:"8",temp:"96.8°F"}, pertinent_findings:"Patient has slow, shallow respirations with snoring airway sounds. SpO2 is 88% and improving slightly with jaw thrust. No obvious trauma. Pupils are equal and sluggish. Glucose is 74 mg/dL. Bladder incontinence noted.", teaching_points:"1. Altered mental status from presumed alcohol intoxication still requires a blood glucose check — hypoglycemia and alcohol intoxication can look identical and missing a low blood sugar is dangerous. 2. Airway positioning is critical in the intoxicated patient — the recovery position (lateral recumbent) protects the airway from aspiration if vomiting occurs; monitor continuously." },
  { dispatch_line:"Medic 12, Big Daddy's Tacos — pregnant female, abdominal pain and possible labor.", chief_complaint:"Pregnant female, active labor contractions", scene_description:"A visibly pregnant female is leaning against the side of the building. Her friend says her water broke about 20 minutes ago and she is having contractions every 3 minutes. She is moaning with each contraction and says she feels pressure like she needs to push.", patient_info:"26-year-old female, 38 weeks gestation, PMH: normal prenatal care, G2P1.", vitals:{bp:"118/74",hr:"96",rr:"18",spo2:"99%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Contractions every 2-3 minutes lasting 60 seconds. Patient says she has strong urge to push. Crowning is NOT yet visible on inspection. Membranes have ruptured. No vaginal bleeding. Previous vaginal delivery.", teaching_points:"1. If crowning is present, delivery is imminent — prepare your OB kit immediately and do not attempt to hold back or delay delivery; guide, do not pull. 2. If delivery is not imminent (no crowning, contractions spaced), transport rapidly in the left lateral position to reduce vena cava compression and improve maternal cardiac output." },
  { dispatch_line:"Medic 12, Big Daddy's Tacos — male patient, 20s, possible drug reaction after eating food laced with unknown substance.", chief_complaint:"Agitated, hallucinating, altered mental status", scene_description:"A young male is pacing erratically outside the taco stand. He is sweating profusely, speaking to people who are not there, and has removed his shirt. Bystanders say he ate something and started acting strange within 20 minutes. He is combative when approached.", patient_info:"23-year-old male, PMH: unknown, no medical alert.", vitals:{bp:"168/102",hr:"138",rr:"24",spo2:"97%",gcs:"13",temp:"103.2°F"}, pertinent_findings:"Patient is extremely agitated, diaphoretic, and hyperthemic. Pupils are widely dilated bilaterally. Skin is hot and flushed. He is moving all extremities with significant strength. Clenching jaw intermittently.", teaching_points:"1. Stimulant toxidrome (sympathomimetic) presents with hypertension, tachycardia, hyperthermia, dilated pupils, and agitation — remove from hot environment, cool the patient, and transport; hyperthermia above 104°F is a serious complication. 2. Agitated patients can deteriorate suddenly to combative or unconscious — ensure your own safety, call for law enforcement if needed, and monitor for airway compromise if sedation becomes necessary." },
  { dispatch_line:"Medic 12, Big Daddy's Tacos — female, fell from a bicycle, head injury.", chief_complaint:"Head injury, brief loss of consciousness", scene_description:"A female cyclist is sitting on the curb. Witnesses say she hit a pothole near the taco stand, flew over the handlebars, and was briefly unconscious for approximately 30 seconds. She is now alert but confused about what happened. She was wearing a helmet that is now cracked.", patient_info:"31-year-old female, PMH: none.", vitals:{bp:"128/78",hr:"86",rr:"16",spo2:"99%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"Patient has a 4cm laceration to the forehead with minor bleeding, now controlled. She is confused, cannot recall the crash, and asks the same questions repeatedly. Cracked helmet suggests significant impact force. No obvious deformity to neck on inspection.", teaching_points:"1. Loss of consciousness even briefly, post-traumatic amnesia, and a cracked helmet are all red flags for significant traumatic brain injury — immobilize the spine and transport to a trauma center regardless of current neurological status. 2. A GCS of 14 can still represent a serious TBI — do not be reassured by a patient who appears 'just confused'; trending GCS on serial assessments is more informative than a single reading." },
],

bd_diner: [
  { dispatch_line:"Medic 12, Big Daddy's All-Night Diner, 820 Papa Drive — male trucker, chest pain, radiating to jaw.", chief_complaint:"Chest pressure, jaw pain, diaphoresis", scene_description:"A large male trucker is seated in a corner booth. The overnight waitress says he came in an hour ago, ordered food, barely ate, and has been sitting there looking pale. He is gripping the table edge and says his chest has been tight for about 45 minutes.", patient_info:"61-year-old male, PMH: hypertension, Type 2 diabetes, smoker.", vitals:{bp:"174/102",hr:"88",rr:"20",spo2:"95%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Patient describes 7/10 pressure radiating to the jaw and left shoulder. Diaphoretic and pale. Lung sounds clear. Denies shortness of breath. Last meal was 2 hours ago. Takes metformin and lisinopril. Has not taken his medications today.", teaching_points:"1. Diabetic patients can have atypical MI presentations with jaw pain, neck pain, or epigastric discomfort instead of classic chest pain — a high index of suspicion is required; treat as cardiac until proven otherwise. 2. Position of comfort for cardiac chest pain is typically semi-Fowler's — avoid supine if the patient feels worse lying flat, as this can worsen venous return." },
  { dispatch_line:"Medic 12, Big Daddy's All-Night Diner — night shift worker, 50s, diabetic emergency, found at table.", chief_complaint:"Unresponsive, diabetic emergency", scene_description:"A female cook is slumped over at the break room table during her 3 AM break. A coworker could not wake her. She is a known diabetic and her coworker reports she skipped dinner and worked a double shift. An empty soda can and her diabetic kit are on the table.", patient_info:"54-year-old female, PMH: Type 2 diabetes on insulin.", vitals:{bp:"98/58",hr:"112",rr:"14",spo2:"97%",gcs:"6",temp:"97.8°F"}, pertinent_findings:"Patient is unresponsive to verbal but withdraws to pain. Skin is cold and clammy. Glucometer reads 22 mg/dL. No smell of alcohol. Pupils equal and reactive. No obvious trauma.", teaching_points:"1. A blood glucose of 22 mg/dL is critically low — a patient who cannot protect their airway cannot receive oral glucose; this patient needs IV dextrose (ALS) or glucagon IM if available in your scope. 2. Know your local protocol for severe hypoglycemia in an unresponsive patient — transport immediately after initial treatment and never leave a hypoglycemic patient alone even after apparent recovery." },
  { dispatch_line:"Medic 12, Big Daddy's All-Night Diner — male, 30s, behavioral emergency, threatening staff.", chief_complaint:"Acute behavioral emergency, agitated and threatening", scene_description:"You arrive to find police are on scene with a male who is barricaded in a booth. He is yelling about being followed and has thrown plates. He has a laceration on his hand from broken dishes. He is refusing to let anyone approach him. No weapons visible.", patient_info:"35-year-old male, PMH: reported schizophrenia by wife on phone.", vitals:{bp:"unable to obtain",hr:"unable to obtain",rr:"elevated",spo2:"unable to obtain",gcs:"unable to formally assess",temp:"unknown"}, pertinent_findings:"Patient is highly agitated, not making coherent responses, and making paranoid statements. No focal deficits observed from a distance. Hand laceration is bleeding but not arterial. Wife states he ran out of his antipsychotic medication 3 days ago.", teaching_points:"1. Safety first in behavioral emergencies — do not approach an agitated patient without law enforcement present; your job is medical support, not restraint. 2. Always consider a medical cause for behavioral changes (hypoglycemia, head injury, stimulant use, hypoxia) before assuming a purely psychiatric etiology — a blood glucose and SpO2 should be obtained at the first safe opportunity." },
  { dispatch_line:"Medic 12, Big Daddy's All-Night Diner — elderly female, sudden onset severe headache.", chief_complaint:"Worst headache of my life, sudden onset", scene_description:"An elderly female is sitting rigidly upright in a booth. She tells you she was eating her breakfast when she suddenly got a headache so severe she thought her head exploded. She has not vomited but feels extremely nauseated. She has not had a headache like this before.", patient_info:"68-year-old female, PMH: hypertension, takes amlodipine.", vitals:{bp:"198/114",hr:"76",rr:"16",spo2:"98%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Patient describes 10/10 sudden onset headache, worst of her life. Neck stiffness noted on assessment. No focal neurological deficits. Pupils equal and reactive. No history of migraines. Severely hypertensive.", teaching_points:"1. Sudden onset 'thunderclap' headache described as the worst of the patient's life is a subarachnoid hemorrhage until proven otherwise — this is a neurological emergency requiring rapid transport to a stroke/neuro center. 2. Neck stiffness (nuchal rigidity) combined with a severe headache suggests meningeal irritation from blood in the CSF — do not delay transport attempting to further investigate; document and go." },
],

bd_coffee: [
  { dispatch_line:"Medic 12, Big Daddy Brews, 250 Throne Ave — young adult, seizure activity, now post-ictal.", chief_complaint:"Seizure, first episode, post-ictal", scene_description:"A college-age male is on the floor behind the counter. Coworkers say he suddenly stiffened and began shaking while making an espresso. The seizure lasted about 90 seconds. He is now breathing on his own but is confused and won't answer questions appropriately.", patient_info:"21-year-old male, PMH: none, denies recreational drug use per coworker.", vitals:{bp:"138/82",hr:"104",rr:"14",spo2:"97%",gcs:"12",temp:"98.8°F"}, pertinent_findings:"First-ever witnessed seizure in a young adult with no prior history. Currently post-ictal, confused. No tongue laceration, no incontinence noted. Glucose is 96 mg/dL. No fever. Pupils equal, slightly sluggish.", teaching_points:"1. A first-time seizure in an adult always requires transport and medical evaluation — the cause is unknown and ranges from benign (fever, low sodium) to serious (brain tumor, meningitis, cardiac arrhythmia). 2. Document seizure duration precisely — a seizure lasting more than 5 minutes is status epilepticus, a medical emergency requiring ALS response and rapid transport." },
  { dispatch_line:"Medic 12, Big Daddy Brews — barista, 20s, possible anaphylaxis to bee sting in outdoor seating area.", chief_complaint:"Bee sting, generalized hives, throat tightening", scene_description:"A female barista is sitting on a stool near the outdoor seating area. She was stung on the neck while working outside. Within minutes she developed itching, hives across her chest and arms, and is now saying her throat feels tight. She appears anxious and is scratching her arms.", patient_info:"24-year-old female, PMH: known bee allergy, normally carries an EpiPen — left it at home today.", vitals:{bp:"94/56",hr:"126",rr:"26",spo2:"93%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Widespread urticaria on trunk and arms. Mild angioedema of the lips. Audible wheeze. Hypotensive and tachycardic. Stinger is still visible in the neck. Anxious and cooperative.", teaching_points:"1. Anaphylaxis with hypotension and respiratory compromise is a life threat — epinephrine IM (per protocol) is the drug of choice; antihistamines alone are NOT sufficient and do not prevent airway closure. 2. Remove the bee stinger by scraping with a card edge — do NOT use tweezers as squeezing the venom sac injects more venom." },
  { dispatch_line:"Medic 12, Big Daddy Brews — male customer, mid-50s, syncope, fell from barstool.", chief_complaint:"Syncope, fell and struck head", scene_description:"A male is on the floor next to an overturned barstool near the counter. A witness says he stood up suddenly, said he felt dizzy, and then collapsed. He was unconscious for about 20 seconds and is now alert but confused and has a bump on the back of his head.", patient_info:"56-year-old male, PMH: hypertension, takes metoprolol and lisinopril.", vitals:{bp:"88/54",hr:"52",rr:"16",spo2:"98%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Patient is bradycardic and hypotensive. He is on a beta blocker. No active bleeding from head. Occipital hematoma palpated. Denies chest pain. States he had not eaten yet today and had two cups of coffee on an empty stomach.", teaching_points:"1. Syncope with bradycardia in a patient on a beta blocker raises concern for medication effect, cardiac arrhythmia, or orthostatic hypotension — obtain orthostatic vitals if the patient is stable and transport for full cardiac workup. 2. Any syncope with a resulting fall and head strike should be treated as potential TBI — even if the patient is now alert and oriented, they need imaging to rule out intracranial injury." },
  { dispatch_line:"Medic 12, Big Daddy Brews — child, approximately 3 years old, ingested unknown quantity of coffee beans.", chief_complaint:"Pediatric ingestion, caffeine toxicity", scene_description:"A mother is holding a 3-year-old who is trembling and crying. She was at a table with the child and looked away for a moment, and the child grabbed a bag of espresso beans from the counter display and ate an unknown number. The child is now shaking and vomited once.", patient_info:"3-year-old male, PMH: none, weight approximately 14 kg.", vitals:{bp:"118/72",hr:"168",rr:"28",spo2:"98%",gcs:"15",temp:"99.0°F"}, pertinent_findings:"Child is tremulous, tachycardic, and tachypneic. Alert and crying. Pupils dilated. Vomited once en route. Approximately 30 espresso beans missing from the display bag. Skin is flushed and moist.", teaching_points:"1. Caffeine toxicity in small children can be serious — symptoms include tachycardia, tremors, vomiting, and in severe cases seizures; transport all pediatric ingestions regardless of apparent current stability. 2. Always bring the container or substance involved in a pediatric ingestion to the hospital — the name, concentration, and quantity help poison control and the ER determine treatment." },
],

bd_grocery: [
  { dispatch_line:"Medic 12, Big Daddy's Food King, 180 Big Daddy Blvd — male, 60s, collapsed in the produce section, CPR in progress.", chief_complaint:"Cardiac arrest, bystander CPR in progress", scene_description:"You find a heavyset male on the floor in the produce section. A store employee is performing CPR. An AED is visible in a wall mount near the customer service desk approximately 20 feet away. The man's wife is nearby and says he just grabbed his chest and fell.", patient_info:"63-year-old male, PMH: unknown per wife, 'healthy' she says, no medications.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Pulseless and apneic. Bystander CPR has been in progress approximately 2 minutes. AED is available. Wife reports no known cardiac history but says he has been under severe stress for months.", teaching_points:"1. Get the AED on the patient as fast as possible — every minute without defibrillation in a shockable rhythm decreases survival by 7-10%; do not delay analysis waiting for ALS. 2. Rotate your compressor every 2 minutes to prevent fatigue and maintain compression quality — studies show compressor effectiveness drops significantly after 90 seconds." },
  { dispatch_line:"Medic 12, Big Daddy's Food King — elderly female, fall from a step stool in the canned goods aisle.", chief_complaint:"Fall, wrist and shoulder pain", scene_description:"A store employee found an elderly female sitting on the floor in aisle 7. She was reaching for a can on a high shelf using a step stool and fell off. She is alert and talking, holding her right arm against her body. Her wrist is visibly deformed.", patient_info:"72-year-old female, PMH: osteoporosis, takes calcium, vitamin D, and warfarin.", vitals:{bp:"144/86",hr:"90",rr:"16",spo2:"98%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Obvious deformity of the right distal forearm consistent with a Colles fracture. Right shoulder pain on palpation and limited ROM. Distal CSM intact in right hand. Patient is on warfarin — bleeding risk elevated. No head strike per patient.", teaching_points:"1. Splint fractures in the position found — do not attempt to realign or straighten a deformed extremity; immobilize the joint above and below, assess and document CSM before and after splinting. 2. Warfarin use significantly increases bleeding risk even with minor trauma — document this clearly in your report and communicate to the receiving facility as it affects their treatment approach." },
  { dispatch_line:"Medic 12, Big Daddy's Food King — child, 4 years old, found unresponsive near the pharmacy counter, possible ingestion.", chief_complaint:"Pediatric unresponsive, unknown ingestion", scene_description:"A 4-year-old boy is lying on the floor near the pharmacy pickup counter. His mother says she set her purse down while talking to the pharmacist and the child got into it. Her purse contains various prescription medications. The child is barely responsive.", patient_info:"4-year-old male, PMH: none, weight approximately 16 kg.", vitals:{bp:"78/44",hr:"48",rr:"8",spo2:"84%",gcs:"6",temp:"97.0°F"}, pertinent_findings:"Child is minimally responsive with slow, irregular respirations. Pupils are pinpoint bilaterally. Skin is pale and moist. Oxygen saturation critically low. Mother's purse contains oxycodone, lorazepam, and blood pressure medications.", teaching_points:"1. Pediatric opioid ingestion can kill rapidly — this child has classic opioid toxidrome (pinpoint pupils, respiratory depression, decreased LOC); support ventilation with BVM immediately and administer naloxone per your protocol. 2. In an unknown pediatric ingestion, gather ALL medications from the scene and bring them to the hospital — the ER needs to know what was possibly ingested to provide the right antidote or treatment." },
  { dispatch_line:"Medic 12, Big Daddy's Food King — female, 30s, severe allergic reaction at the deli counter.", chief_complaint:"Anaphylaxis after eating deli sample", scene_description:"A female is sitting on the floor near the deli counter. She sampled a product and within five minutes developed facial swelling, hives, and is now struggling to breathe. The deli worker looks shocked and says the product may have contained tree nuts.", patient_info:"31-year-old female, PMH: tree nut allergy, normally carries an EpiPen.", vitals:{bp:"86/52",hr:"132",rr:"28",spo2:"91%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Severe angioedema of face, lips, and tongue. Stridor present. Widespread urticaria across trunk. Hypotensive and tachycardic. SpO2 91% and declining. Her EpiPen is in her car in the parking lot.", teaching_points:"1. Anaphylaxis with stridor means the airway is closing — this is immediately life-threatening; epinephrine IM is the only treatment that reverses this; position of comfort, O2, and rapid transport while preparing to manage the airway. 2. Biphasic anaphylaxis (return of symptoms 1-8 hours after apparent resolution) occurs in up to 20% of cases — all anaphylaxis patients must be transported even if they feel better after treatment." },
],

bd_dollar: [
  { dispatch_line:"Medic 12, Big Daddy's Dollar Deals, 450 Papa Drive — male, stabbed during a robbery attempt.", chief_complaint:"Stab wound to chest, difficulty breathing", scene_description:"Police are on scene outside. A male store employee was stabbed once in the right chest during an attempted robbery. He is sitting against the exterior wall, leaning toward the right side. His breathing is labored and unequal. There is a small puncture wound visible on the right chest.", patient_info:"28-year-old male, PMH: none.", vitals:{bp:"100/66",hr:"122",rr:"28",spo2:"90%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Decreased breath sounds on the right. Trachea appears midline. SpO2 90% and declining. Patient says it hurts to breathe. Wound is approximately 1.5cm, not sucking air currently. Subcutaneous emphysema not yet palpable. Tachycardic and anxious.", teaching_points:"1. A chest wound that penetrates the chest wall is a potential open pneumothorax — apply a vented chest seal (or commercial equivalent) to prevent tension pneumothorax development while allowing air to escape on exhalation. 2. If a patient with a chest wound deteriorates with declining SpO2, tracheal deviation, and absent breath sounds, suspect tension pneumothorax — this is an ALS emergency but your job is rapid transport and airway support." },
  { dispatch_line:"Medic 12, Big Daddy's Dollar Deals — elderly male, fell in the store, head laceration and confusion.", chief_complaint:"Ground level fall, head laceration, confused", scene_description:"An elderly male is sitting in an aisle surrounded by scattered products he knocked off the shelf when he fell. Staff say he was walking with a cane and tripped on a mat near the entrance. He has a bleeding laceration on his forehead and is confused about where he is.", patient_info:"80-year-old male, PMH: dementia, hypertension, atrial fibrillation, takes Xarelto.", vitals:{bp:"156/92",hr:"84 irregular",rr:"16",spo2:"96%",gcs:"13",temp:"98.2°F"}, pertinent_findings:"3cm forehead laceration with active but controllable bleeding. Baseline dementia makes neuro assessment difficult — family members are unavailable by phone. On anticoagulation therapy. GCS 13 (eyes 4, verbal 3, motor 6).", teaching_points:"1. Anticoagulated elderly patients with head trauma require emergent imaging even with minor mechanisms — intracranial bleeding can expand slowly; the current exam is not reliable in ruling out a serious injury. 2. A patient's baseline mental status matters — a GCS of 13 in a patient with dementia may be near their baseline or may represent a significant change; always try to get a baseline from family or caregivers." },
  { dispatch_line:"Medic 12, Big Daddy's Dollar Deals — female customer, 40s, heat exhaustion, collapsed near the entrance.", chief_complaint:"Heat exhaustion, syncope in parking lot", scene_description:"A female was found collapsed in the hot parking lot next to her car. A bystander dragged her into the store entrance where it is air conditioned. She is regaining consciousness but is very confused, weak, and nauseous. Outside temperature is 97°F.", patient_info:"43-year-old female, PMH: hypertension, takes hydrochlorothiazide.", vitals:{bp:"96/58",hr:"116",rr:"20",spo2:"98%",gcs:"14",temp:"103.8°F"}, pertinent_findings:"Skin is hot, flushed, and moist. Patient is confused, nauseous, and weak. Temperature 103.8°F orally. Diuretic use increases dehydration risk. Has been outside shopping in the heat for 2 hours.", teaching_points:"1. Distinguish heat exhaustion (elevated temp, moist skin, altered mentation) from heat stroke (temp above 104°F, hot DRY skin, severe mental status changes) — both are emergencies but heat stroke is immediately life threatening and requires aggressive cooling. 2. Begin cooling immediately — move to a cool environment, remove excess clothing, apply cool wet cloths to the neck, axilla, and groin, and transport; oral fluids only if the patient is alert and can swallow safely." },
  { dispatch_line:"Medic 12, Big Daddy's Dollar Deals — child, 2 years old, unattended in a hot car in the parking lot.", chief_complaint:"Pediatric hyperthermia, found in hot car", scene_description:"A bystander broke a car window after seeing a toddler alone in a vehicle in the parking lot. Outside temperature is 94°F. The car interior is estimated at over 115°F by the time you arrive. The child is limp, not crying, and barely responsive.", patient_info:"Approximately 2-year-old female, PMH: none.", vitals:{bp:"74/40",hr:"168",rr:"36 shallow",spo2:"94%",gcs:"7",temp:"106.2°F"}, pertinent_findings:"Child is critically hyperthermic and minimally responsive. Skin is hot and dry. Tachycardic with weak radial pulse. Respirations rapid and shallow. No response to voice, moaning to pain only.", teaching_points:"1. Pediatric heat stroke is a critical emergency — begin aggressive cooling immediately (cool wet towels, ice packs to neck/axilla/groin, air conditioning); do not delay transport but cool en route. 2. A core temperature above 105°F in a child can cause brain damage, seizures, and cardiac arrest — communicate the severity and temperature to the receiving facility immediately on radio." },
],

bd_pharmacy: [
  { dispatch_line:"Medic 12, Big Daddy's Rx Pharmacy, 240 Crown St — elderly male, possible medication overdose.", chief_complaint:"Altered mental status, possible medication overdose", scene_description:"An elderly male was found by the pharmacist confused and lethargic in the waiting area. He had just picked up his monthly medications. A bag of prescriptions is in his lap and several empty blister packs are on the seat beside him. His wife is not present.", patient_info:"79-year-old male, PMH: hypertension, CHF, atrial fibrillation, depression.", vitals:{bp:"82/48",hr:"42",rr:"10",spo2:"92%",gcs:"10",temp:"97.4°F"}, pertinent_findings:"Severely bradycardic and hypotensive. The empty blister packs include metoprolol and digoxin — both of which can cause fatal bradycardia in overdose. Pupils are equal and slightly dilated. Patient responds to sternal rub only.", teaching_points:"1. Beta blocker and digoxin overdose both cause profound bradycardia and hypotension — this combination is potentially fatal; rapid transport, airway management, and communication to the ER about the suspected medications are your priorities. 2. Always bring ALL medications and empty packaging to the hospital with a medication overdose patient — the ER needs to know exactly what the patient took and how much to administer the correct antidote." },
  { dispatch_line:"Medic 12, Big Daddy's Rx Pharmacy — elderly female, anaphylaxis after receiving a vaccine.", chief_complaint:"Anaphylaxis following flu vaccine", scene_description:"The pharmacist meets you at the door. An 82-year-old female received a routine flu shot 10 minutes ago and developed progressive difficulty breathing, hives, and now has low blood pressure. She is in the vaccine area, semi-conscious in a recliner chair.", patient_info:"82-year-old female, PMH: CHF, hypertension, atrial fibrillation.", vitals:{bp:"78/44",hr:"122 irregular",rr:"28",spo2:"88%",gcs:"12",temp:"98.0°F"}, pertinent_findings:"Urticaria across chest and neck. Audible wheeze bilaterally. Angioedema of the lips. Semi-conscious and responsive only to voice. The pharmacist administered epinephrine 0.3mg IM 5 minutes ago with minimal improvement.", teaching_points:"1. Post-vaccination anaphylaxis that does not respond to an initial epinephrine dose may require a second dose — know your protocol for repeat epinephrine dosing; biphasic response is common and these patients must be transported even if they improve. 2. Managing anaphylaxis in a patient with CHF and atrial fibrillation is complex — the tachycardia from epinephrine can worsen cardiac function; communicate the full medical history to the ER and transport rapidly." },
  { dispatch_line:"Medic 12, Big Daddy's Rx Pharmacy — female, 30s, seizure in the pharmacy.", chief_complaint:"Active generalized seizure, ongoing", scene_description:"A female customer is actively seizing in the medication pick-up line. The pharmacist says the seizure has been going on for at least 4 minutes and shows no sign of stopping. She has fallen to the floor and is in a full tonic-clonic episode. No bystanders know her medical history.", patient_info:"33-year-old female, PMH: unknown, no medical alert jewelry.", vitals:{bp:"unable",hr:"unable",rr:"irregular, seized",spo2:"unable",gcs:"3",temp:"unknown"}, pertinent_findings:"Active generalized tonic-clonic seizure now entering its fifth minute. Duration suggests status epilepticus. Airway at risk. No tongue lac visible from observation. No obvious trauma from fall. History unknown.", teaching_points:"1. A seizure lasting more than 5 minutes is status epilepticus — this is a medical emergency requiring ALS intervention (benzodiazepines); at the EMT-B level, protect the airway, prevent injury, administer O2, and transport emergently while requesting ALS intercept. 2. During an active seizure, do not restrain the patient or put anything in their mouth — your role is airway positioning, padding, and preparation for post-ictal airway management." },
  { dispatch_line:"Medic 12, Big Daddy's Rx Pharmacy — male, 70s, chest pain after picking up nitroglycerin prescription.", chief_complaint:"Chest pain, possible nitroglycerin reaction", scene_description:"A pharmacist flagged down a male patient in the parking lot. He had just picked up a new prescription of nitroglycerin and took one tablet for chest pain he had before entering the store. He is now sitting on a parking bumper looking pale and says he feels very dizzy.", patient_info:"71-year-old male, PMH: CAD, prior MI, takes sildenafil and aspirin.", vitals:{bp:"72/44",hr:"104",rr:"18",spo2:"97%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Patient is severely hypotensive after nitroglycerin administration. He is alert but feels faint. He admits he took sildenafil (Viagra) yesterday. Combination of nitrates and PDE5 inhibitors causes profound hypotension. Chest pain is still present rated 5/10.", teaching_points:"1. Nitroglycerin is absolutely contraindicated in patients who have taken a PDE5 inhibitor (Viagra, Cialis, Levitra) within 24-48 hours — the combination causes life-threatening hypotension; always ask about erectile dysfunction medications before considering NTG. 2. Hypotension following nitroglycerin in this context is a medical emergency — lay the patient supine or in Trendelenburg if tolerated, apply O2, and transport rapidly; do not administer additional nitroglycerin." },
],

bd_cbd: [
  { dispatch_line:"Medic 12, Big Daddy's CBD and Wellness, 310 Throne Ave — male customer, altered mental status after consuming kratom product.", chief_complaint:"Altered mental status, kratom ingestion", scene_description:"A male customer is slumped in a display chair near the back of the store. The store clerk says he came in about an hour ago, purchased a high-dose kratom extract, consumed it in the store, and has become increasingly sedated. He is responsive but difficult to arouse.", patient_info:"29-year-old male, PMH: opioid use disorder, on suboxone.", vitals:{bp:"96/58",hr:"62",rr:"10",spo2:"92%",gcs:"10",temp:"97.6°F"}, pertinent_findings:"Patient is sedated with slow, shallow respirations. Pupils are mildly constricted. Skin is pale and moist. SpO2 92% improving to 96% with jaw thrust. He is on suboxone which may interact with kratom's opioid agonist effects.", teaching_points:"1. Kratom has partial opioid agonist activity and can cause respiratory depression similar to opioids, especially in high doses or combined with other opioids or opioid partial agonists — treat as suspected opioid toxicity and follow your naloxone protocol. 2. A patient on suboxone (buprenorphine/naloxone) who ingests an opioid agonist can have unpredictable effects — suboxone occupies opioid receptors and may complicate naloxone response; transport for medical evaluation regardless of your naloxone response." },
  { dispatch_line:"Medic 12, Big Daddy's CBD and Wellness — teenager, 16 years old, ingested CBD edibles, parents on scene.", chief_complaint:"Pediatric ingestion, excessive CBD edibles, lethargic", scene_description:"A 16-year-old female is sitting on a floor cushion with her parents standing over her. She purchased gummies from the store (age check failure) and consumed the entire bag. She is very drowsy, giggling inappropriately, and her parents say she is not acting normally for her.", patient_info:"16-year-old female, PMH: anxiety, takes escitalopram.", vitals:{bp:"102/64",hr:"88",rr:"14",spo2:"98%",gcs:"13",temp:"98.4°F"}, pertinent_findings:"Alert but highly sedated and confused. Mild tachycardia. Eyes bloodshot, pupils slightly dilated. Giggles inappropriately at questions. Ingested approximately 1000mg of CBD. The escitalopram interaction with high-dose CBD can increase sedation.", teaching_points:"1. High-dose CBD can cause significant sedation, especially in teenagers and in combination with SSRIs — while rarely life-threatening in isolation, monitor the airway and transport for evaluation since product potency and contents may be inconsistent. 2. Always bring the product packaging with a drug ingestion — ingredients, dosage, and concentration on the label help the ER assess actual risk and manage accordingly." },
  { dispatch_line:"Medic 12, Big Daddy's CBD and Wellness — female employee, 20s, syncope while at work.", chief_complaint:"Syncope, fell and hit counter, laceration to chin", scene_description:"A female store clerk fainted behind the counter and struck her chin on the edge of the display case. A customer heard the fall and found her on the floor. She is regaining consciousness and has a bleeding laceration on her chin. She says she has not eaten all day.", patient_info:"23-year-old female, PMH: none, no medications, reports she is pregnant — approximately 8 weeks.", vitals:{bp:"92/58",hr:"96",rr:"16",spo2:"99%",gcs:"15",temp:"98.2°F"}, pertinent_findings:"Alert and oriented. Chin laceration approximately 2cm with minor bleeding, controlled with pressure. Hypotensive at baseline. Pale conjunctiva. States she has had morning sickness and cannot keep food down. First trimester pregnancy confirmed by patient.", teaching_points:"1. Syncope in early pregnancy can result from relative hypotension due to vasodilation and dehydration from hyperemesis — assess for ectopic pregnancy as a life threat before attributing symptoms to benign causes; report LMP and pregnancy status to the ER. 2. Transport pregnant patients in the left lateral position when possible to relieve vena cava compression, which worsens hypotension; document the pregnancy clearly in your report." },
  { dispatch_line:"Medic 12, Big Daddy's CBD and Wellness — male customer, 60s, acute anxiety attack, hyperventilating.", chief_complaint:"Acute anxiety, hyperventilation, chest pain", scene_description:"A male customer is pacing near the entrance. He says he came in to buy something for his anxiety but had a panic attack in the store. He is breathing very fast, clutching his chest, and says his hands and face feel numb. He is convinced he is having a heart attack.", patient_info:"61-year-old male, PMH: generalized anxiety disorder, hypertension, family history of cardiac disease.", vitals:{bp:"162/98",hr:"118",rr:"36",spo2:"99%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Hyperventilating with circumoral and bilateral hand tingling (carpopedal spasm). Chest pain described as tightness, 5/10, no radiation. Skin warm and dry. No diaphoresis. Has had multiple prior panic attacks per patient history.", teaching_points:"1. A 61-year-old male with hypertension, family cardiac history, and chest pain is a cardiac patient until proven otherwise — do not assume panic attack in a high-risk demographic; treat and transport as potential ACS. 2. Calm reassurance, a slow deliberate tone, and reducing stimulation are genuine tools in managing panic attacks — but they are adjuncts to, not substitutes for, appropriate medical assessment and transport." },
],

bd_smoke: [
  { dispatch_line:"Medic 12, Big Daddy's Smoke Shack, 330 Throne Ave — male, COPD exacerbation, severe difficulty breathing.", chief_complaint:"COPD exacerbation, severe shortness of breath", scene_description:"A male regular customer is seated outside the shop on a bench, leaning forward with his hands on his knees. The store owner called 911 because the man could barely walk from the parking lot. He is using accessory muscles and can only say two to three words at a time.", patient_info:"67-year-old male, PMH: severe COPD, CHF, continues to smoke.", vitals:{bp:"154/94",hr:"114",rr:"34",spo2:"82%",gcs:"15",temp:"99.4°F"}, pertinent_findings:"Severe respiratory distress with tripod positioning, pursed-lip breathing, and accessory muscle use. Distant breath sounds with expiratory wheeze. SpO2 82% on room air. Prolonged expiration. Barrel chest deformity. Continues to smoke a cigarette on arrival.", teaching_points:"1. In COPD patients, use controlled flow oxygen (2-3 L/min by NC or 28% Venturi) to maintain SpO2 of 88-92% — while the hypoxic drive concern is often overstated, uncontrolled high-flow O2 in severe COPD can suppress respiratory drive in some patients; titrate to effect. 2. A COPD patient in severe distress with SpO2 of 82% is in respiratory failure — if your protocols allow CPAP, this is a primary indication; if not, prepare for BVM ventilation and request ALS intercept." },
  { dispatch_line:"Medic 12, Big Daddy's Smoke Shack — teenager, 17 years old, vaping-associated lung injury.", chief_complaint:"Progressive shortness of breath, fever, vaping history", scene_description:"A 17-year-old male is sitting inside the store with his father. He bought vaping products here and has been vaping heavily for six months. Over the past week he developed fever, progressive shortness of breath, and fatigue. Today he could barely walk to the car.", patient_info:"17-year-old male, PMH: none, heavy THC and nicotine vape user x6 months.", vitals:{bp:"118/74",hr:"112",rr:"28",spo2:"89%",gcs:"15",temp:"101.8°F"}, pertinent_findings:"Bilateral crackles on auscultation. Febrile at 101.8°F. SpO2 89% on room air. Tachycardic and tachypneic. No prior respiratory history. Progressive dyspnea over 7 days. Classic presentation for EVALI (e-cigarette associated lung injury).", teaching_points:"1. EVALI (e-cigarette or vaping product use-associated lung injury) can cause severe bilateral lung injury in young people with no prior medical history — a teenager with progressive dyspnea and vaping history needs O2, transport, and chest imaging urgently. 2. Always ask about vaping history in young patients with respiratory complaints — it is not volunteered easily by teenagers; EVALI can present similarly to pneumonia or pulmonary edema." },
  { dispatch_line:"Medic 12, Big Daddy's Smoke Shack — female, 40s, fall in the parking lot, struck head on curb.", chief_complaint:"Head trauma from fall, LOC unknown", scene_description:"A female is sitting on the curb holding her head. Witnesses say she slipped on a wet spot in the parking lot and struck the back of her head on the curb. She was possibly briefly unresponsive — witnesses are unsure. She is alert now but says she is confused about what happened.", patient_info:"44-year-old female, PMH: migraines, takes sumatriptan and naproxen.", vitals:{bp:"134/82",hr:"88",rr:"16",spo2:"99%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"2cm occipital laceration with controlled bleeding. She cannot recall the fall or the moments immediately after. Complains of headache and neck pain. Nausea present. No focal deficits. Denies alcohol use. GCS 15 now.", teaching_points:"1. Post-traumatic amnesia (not remembering the event or period after impact) is evidence of at least a brief loss of consciousness and indicates concussion at minimum — this patient needs spinal precautions, imaging, and observation regardless of current GCS. 2. Occipital head strikes can injure the cervical spine even without deformity — treat as a spinal injury until imaging rules it out; apply a cervical collar and use a long spine board or scoop stretcher per your protocol." },
  { dispatch_line:"Medic 12, Big Daddy's Smoke Shack — male employee, chest pain, history of recent MI.", chief_complaint:"Recurrent chest pain, prior MI 3 weeks ago", scene_description:"A male employee is sitting behind the counter gripping his chest. He returned to work just 10 days after his MI. He says the chest pain started about 30 minutes ago and feels exactly like his heart attack did. His coworker called 911 despite the patient's protests.", patient_info:"58-year-old male, PMH: MI 3 weeks ago, takes aspirin, metoprolol, atorvastatin, plavix.", vitals:{bp:"146/90",hr:"94",rr:"20",spo2:"95%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Chest pressure 7/10 with left arm radiation. Diaphoretic. Lung sounds clear. The patient is still smoking actively. He is on dual antiplatelet therapy post-stent placement. Last took his medications this morning.", teaching_points:"1. A patient with a recent MI presenting with identical chest pain is having a recurrent ACS until proven otherwise — no amount of reassurance changes this; this patient needs immediate transport to the catheterization lab hospital, not the closest ER. 2. Continuing to smoke post-MI dramatically increases recurrence risk — document tobacco use, communicate to the ER, but do not lecture the patient during the acute event; patient education is not your priority right now." },
],

bd_carwash: [
  { dispatch_line:"Medic 12, Big Daddy's Car Wash, 760 Big Daddy Blvd — male employee, arm caught in conveyor machinery.", chief_complaint:"Traumatic arm injury, machinery entrapment", scene_description:"Fire department is on scene extricating a male employee whose right arm was caught in the conveyor belt mechanism. His arm has been freed but there is significant deformity from mid-forearm to the elbow. He is conscious and screaming in pain.", patient_info:"31-year-old male, PMH: none.", vitals:{bp:"128/82",hr:"128",rr:"24",spo2:"98%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Crush injury with open fracture of the right forearm — bone visible through the wound. Bleeding is moderate and partially controlled by pressure dressings applied by fire. Distal CSM is intact in the fingers. Significant swelling and deformity.", teaching_points:"1. An open fracture carries a serious risk of infection and compartment syndrome — cover the wound with a moist sterile dressing, splint in position found, and transport; do not attempt to push exposed bone back into the wound. 2. Crush injuries may initially appear better than they are — reperfusion of a crushed limb can release myoglobin and potassium into the bloodstream causing kidney failure and cardiac arrhythmias; document mechanism carefully and communicate to the ER." },
  { dispatch_line:"Medic 12, Big Daddy's Car Wash — customer, 70s, unresponsive in vehicle inside the wash bay.", chief_complaint:"Unresponsive elderly male in vehicle", scene_description:"The car wash tunnel stopped when a car failed to exit. Staff found an elderly male slumped over the steering wheel. The car is still running inside the enclosed bay. Staff pulled him out to the parking lot. He has a pulse but is unresponsive.", patient_info:"74-year-old male, PMH: unknown, diabetic alert bracelet visible.", vitals:{bp:"142/86",hr:"78",rr:"12",spo2:"95%",gcs:"7",temp:"98.0°F"}, pertinent_findings:"Unresponsive but has a pulse and spontaneous respirations. Diabetic alert bracelet present. Blood glucose 28 mg/dL — critically low. Car was running in an enclosed space for an unknown time — CO exposure possible. Pupils equal and sluggish.", teaching_points:"1. Always look for a medical alert bracelet — it directly changed your assessment here from 'unknown cause' to a treatable emergency; blood glucose confirmed hypoglycemia as the likely cause. 2. Consider multiple concurrent problems — this patient may have hypoglycemia AND CO exposure from the running vehicle; treat both and communicate both concerns to the receiving facility." },
  { dispatch_line:"Medic 12, Big Daddy's Car Wash — female customer, slipped on wet floor, possible ankle fracture.", chief_complaint:"Slip and fall, ankle deformity", scene_description:"A female customer slipped on the wet concrete floor near the vacuum stations. She is sitting on the ground unable to bear weight on her left ankle. The ankle is visibly deformed with significant swelling already forming. She is in moderate pain but calm.", patient_info:"38-year-old female, PMH: none.", vitals:{bp:"128/78",hr:"96",rr:"16",spo2:"99%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Left ankle deformity with immediate swelling and ecchymosis. Patient rates pain 6/10. Distal CSM intact. No crepitus felt on gentle palpation. She can wiggle her toes with pain. Mechanism was a simple slip — no head or spinal involvement.", teaching_points:"1. Splint ankle fractures in the position found using a padded board or air splint — assess and document CSM (circulation, sensation, movement) before and after splinting; a change in CSM post-splint requires loosening and reassessment. 2. Do not have the patient try to walk or bear weight to 'test' the injury — attempting ambulation on a fractured ankle can displace the fracture, damage vessels or nerves, or convert a closed fracture to an open one." },
  { dispatch_line:"Medic 12, Big Daddy's Car Wash — male, chemical exposure to eyes from cleaning solution.", chief_complaint:"Eye injury, chemical splash to bilateral eyes", scene_description:"A male employee is at the industrial sink rinsing his eyes when you arrive. He was mixing cleaning chemicals in a bucket and one splashed back into both eyes. He has been rinsing for about 3 minutes. Both eyes are bright red and tearing heavily. He says his vision is blurry.", patient_info:"27-year-old male, PMH: none.", vitals:{bp:"132/80",hr:"102",rr:"18",spo2:"99%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Bilateral conjunctival injection with excessive tearing. Patient cannot keep eyes open due to pain. Vision is reportedly blurry. The chemical used is an alkaline degreaser. Alkaline burns penetrate deeper and longer than acids.", teaching_points:"1. Alkaline chemical eye injuries are more dangerous than acid burns because they continue to penetrate tissue — continuous irrigation with water or saline is the treatment; flush for at least 15-20 minutes and continue irrigation en route to the hospital. 2. Always bring the chemical container or MSDS sheet to the hospital — the identity and pH of the chemical directly affects the ophthalmologist's treatment plan; do not stop irrigation to search for the container, have a bystander bring it." },
],

bd_laundry: [
  { dispatch_line:"Medic 12, Big Daddy's Laundromat, 150 Papa Drive — female, 20s, assaulted in the parking lot.", chief_complaint:"Assault victim, facial trauma and pain", scene_description:"Police have a male in custody near the parking lot. A female is seated inside the laundromat with staff. She has visible bruising and swelling to the left side of her face and is holding her left eye. She is alert and talking but shaken. She is approximately 7 months pregnant.", patient_info:"24-year-old female, 28 weeks pregnant, PMH: none.", vitals:{bp:"126/78",hr:"108",rr:"18",spo2:"99%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Periorbital hematoma and swelling to left eye. Possible zygomatic fracture on palpation. Complains of abdominal pain that she says started after being shoved. Uterine fundus palpable at umbilicus. Fetal movement reported by patient.", teaching_points:"1. Any trauma in a pregnant patient requires fetal monitoring and OB evaluation — even seemingly minor abdominal trauma can cause placental abruption, which may present with abdominal pain, uterine tenderness, and vaginal bleeding. 2. Transport pregnant trauma patients beyond 20 weeks in the left lateral tilt position (30 degrees) to prevent supine hypotension from aortocaval compression; this also improves placental perfusion." },
  { dispatch_line:"Medic 12, Big Daddy's Laundromat — child, 3 years old, unresponsive after getting into commercial cleaning products in the back room.", chief_complaint:"Toddler unresponsive, chemical ingestion", scene_description:"The laundromat owner is holding a limp toddler. A 3-year-old wandered into the supply closet and was found with an open bottle of concentrated laundry detergent. There is detergent around his mouth and he is barely conscious. The closet door was left unlocked.", patient_info:"3-year-old male, PMH: none, weight approximately 15 kg.", vitals:{bp:"80/46",hr:"148",rr:"32",spo2:"90%",gcs:"7",temp:"98.8°F"}, pertinent_findings:"Decreased level of consciousness with detergent residue around mouth. Tachycardic. Excessive drooling and foaming at the mouth. Corrosive chemical burns visible around the lips. Retching but no vomiting yet.", teaching_points:"1. Do NOT induce vomiting in a corrosive ingestion — vomiting re-exposes the esophagus and airway to the caustic material making burns worse; treat airway, administer water per poison control guidance, and transport urgently. 2. Call Poison Control (1-800-222-1222) while en route for guidance on specific chemical ingestions — they can guide the ER on antidote and treatment and you can patch them in via radio or phone." },
  { dispatch_line:"Medic 12, Big Daddy's Laundromat — male, 50s, cardiac arrest in the parking lot.", chief_complaint:"Cardiac arrest, bystander CPR, AED on scene", scene_description:"A male collapsed in the parking lot. A bystander retrieved the AED from inside the laundromat and delivered one shock before you arrived. CPR is in progress. The patient is still pulseless. Your unit arrives 6 minutes after the call.", patient_info:"54-year-old male, PMH: unknown.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Pulseless and apneic. One shock delivered by AED approximately 2 minutes ago per bystander. CPR resumed immediately after. No traumatic injuries noted. Downtime approximately 5-6 minutes total with bystander CPR and defibrillation.", teaching_points:"1. After defibrillation, immediately resume CPR starting with chest compressions — do not pause to check for a pulse after a shock; 2 minutes of CPR after each defibrillation attempt is the standard before reassessing rhythm. 2. Good bystander CPR and early defibrillation are the two interventions that most improve cardiac arrest survival — reinforce this with any bystanders who helped; they made a real difference." },
  { dispatch_line:"Medic 12, Big Daddy's Laundromat — elderly male, 3 AM, unresponsive on the bench.", chief_complaint:"Unresponsive elderly male, possible hypothermia", scene_description:"A 3 AM customer found an elderly man unresponsive on a bench inside the laundromat. He appears to have been there a while. His clothes are wet and it was 38°F outside tonight. He smells faintly of alcohol. He has a faint pulse.", patient_info:"Approximately 65-year-old male, PMH: unknown, appears homeless.", vitals:{bp:"82/50",hr:"42",rr:"6",spo2:"84%",gcs:"5",temp:"88.4°F"}, pertinent_findings:"Core temperature 88.4°F — severe hypothermia. Pulse is weak and bradycardic. Respirations are very slow and shallow. Pupils are equal and sluggish. Skin is pale and cold to the touch on trunk.", teaching_points:"1. Severe hypothermia mimics death — pupils may be fixed, pulse barely palpable, and respirations nearly absent; the saying 'not dead until warm and dead' applies; resuscitate and warm en route before calling any code. 2. Handle hypothermic patients gently — the cold myocardium is extremely irritable and prone to ventricular fibrillation with rough movement; minimize jostling during packaging and keep the patient horizontal." },
],

bd_auto: [
  { dispatch_line:"Medic 12, Big Daddy's Auto Repair, 820 Big Daddy Blvd — mechanic, car fell off lift, crushing injury.", chief_complaint:"Crush injury to legs, car fell from lift", scene_description:"A vehicle fell off a hydraulic lift onto a mechanic's lower legs. Fire department is on scene and the vehicle has been lifted off. The mechanic is conscious and screaming in pain. Both lower legs have significant crush injuries with deformity visible.", patient_info:"36-year-old male, PMH: none.", vitals:{bp:"88/52",hr:"144",rr:"28",spo2:"96%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Bilateral lower extremity crush injuries with deformity and significant swelling. Shock physiology present — tachycardic and hypotensive. Distal CSM diminished in left foot. Entrapment time was approximately 8 minutes.", teaching_points:"1. Crush syndrome develops when prolonged pressure is released — reperfusion releases myoglobin, potassium, and lactic acid into the bloodstream causing cardiac arrhythmias and kidney failure; communicate crush mechanism and duration to the ER immediately. 2. Shock in a trauma patient requires rapid transport — do not delay on scene for extensive packaging; apply traction splints if indicated by protocol, control visible bleeding, and go." },
  { dispatch_line:"Medic 12, Big Daddy's Auto Repair — male, 40s, eye injury from metal fragment during grinding.", chief_complaint:"Eye injury, foreign body, metal fragment", scene_description:"A mechanic was grinding a brake rotor without safety glasses when a fragment struck his right eye. He is sitting at a workbench with his hand over his right eye. He says he can barely see out of it and it feels like something is stuck in the eyeball.", patient_info:"42-year-old male, PMH: none, was not wearing eye protection.", vitals:{bp:"136/84",hr:"90",rr:"16",spo2:"99%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Right eye painful with tearing and visible injection. Patient unable to open eye fully due to pain. No foreign body visible on external inspection with penlight. Possible penetrating eye injury — irregular pupil shape on right side.", teaching_points:"1. Never apply pressure to a suspected penetrating eye injury — use a rigid shield (or a paper cup) over the eye WITHOUT pressure; pressure on a ruptured globe can extrude ocular contents and cause permanent blindness. 2. Cover BOTH eyes to reduce sympathetic eye movement — when one eye moves, the injured eye moves with it; bilateral patching prevents involuntary movement of the injured eye during transport." },
  { dispatch_line:"Medic 12, Big Daddy's Auto Repair — customer in waiting room, 60s, acute stroke symptoms.", chief_complaint:"Sudden slurred speech and left-sided weakness", scene_description:"A female customer waiting for her vehicle began slurring her speech and dropped her coffee cup. A service advisor noticed her left arm hanging limp and called 911. She is sitting in the waiting room chair, awake but clearly struggling to communicate.", patient_info:"63-year-old female, PMH: hypertension, Type 2 diabetes, takes metformin and lisinopril.", vitals:{bp:"196/112",hr:"86",rr:"16",spo2:"97%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"FAST positive — no facial droop, left arm weakness with drift, speech is slurred and word-finding is impaired. Last known well per customer was 20 minutes ago when she was on her phone. Blood glucose 118 mg/dL. No trauma.", teaching_points:"1. The last known well time is the most critical piece of information in a stroke call — it determines eligibility for tPA and mechanical thrombectomy; get it from every available source (witnesses, phone last call time, security cameras) and document precisely. 2. Hypertension is common in acute stroke and should NOT be treated in the field — the brain may depend on elevated pressure to perfuse around the clot; lowering BP before imaging can worsen the stroke." },
  { dispatch_line:"Medic 12, Big Daddy's Auto Repair — toxic fume exposure, employee sprayed with refrigerant.", chief_complaint:"Freon exposure, eye and airway irritation", scene_description:"An employee was working with a vehicle's AC system when a refrigerant line ruptured, spraying his face and chest with liquid Freon. He ran outside immediately and is standing in the lot. He is coughing continuously, his eyes are red and watering, and he says his chest feels tight.", patient_info:"33-year-old male, PMH: mild asthma.", vitals:{bp:"128/78",hr:"106",rr:"24",spo2:"94%",gcs:"15",temp:"97.6°F"}, pertinent_findings:"Bilateral eye irritation with tearing. Expiratory wheeze audible bilaterally — reactive airway from inhalation. Skin on face and chest mildly red. SpO2 94%. No frostbite noted. Complains of chest tightness consistent with bronchospasm.", teaching_points:"1. Refrigerant inhalation can cause significant bronchospasm, especially in patients with underlying asthma — O2, position of comfort, and transport; document the specific refrigerant type if you can safely obtain it as this affects the ER treatment approach. 2. Liquid refrigerant can cause cryogenic burns on skin contact — assess the exposed skin carefully; what looks like redness initially can develop into frostbite injury requiring specific wound care." },
],

bd_club: [
  { dispatch_line:"Medic 12, Big Daddy's Gentleman's Club, 730 Crown St — female, possible drug-facilitated assault, altered mental status.", chief_complaint:"Altered mental status, possible drug ingestion", scene_description:"Security brought a female to the front entrance after she was found non-communicative in a back hallway. She cannot tell you her name or what happened. Friends say she was fine 45 minutes ago and had only two drinks. She is slumped against the wall and barely keeping her eyes open.", patient_info:"22-year-old female, PMH: none.", vitals:{bp:"88/52",hr:"112",rr:"10",spo2:"90%",gcs:"9",temp:"97.2°F"}, pertinent_findings:"Profoundly altered with slow respirations. Two drinks consumed does not match this level of impairment. Pupils are small bilaterally. Unable to walk independently. Skin is pale and cool. No obvious trauma. Urine detected on her clothing.", teaching_points:"1. Profound sedation disproportionate to reported alcohol intake should raise immediate suspicion for drug-facilitated assault — treat as a toxicological emergency, protect her airway, and ensure police are notified as this is a potential crime scene. 2. GHB, benzodiazepines, and other sedating drugs can cause rapid respiratory depression — even a patient who appears 'only drunk' can deteriorate to apnea quickly; monitor respirations continuously and be prepared to ventilate." },
  { dispatch_line:"Medic 12, Big Daddy's Gentleman's Club — male, 30s, altercation outside, laceration to neck.", chief_complaint:"Laceration to neck, possible vascular injury", scene_description:"Police are on scene outside the club. A male was struck with a broken bottle during a fight. He has a laceration to the left lateral neck and is bleeding from it. He is standing but looks pale. The laceration is deep and there is pulsatile bleeding with each heartbeat.", patient_info:"32-year-old male, PMH: none.", vitals:{bp:"94/60",hr:"138",rr:"24",spo2:"95%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Deep laceration to left lateral neck approximately 4cm with pulsatile arterial bleeding suggesting carotid or jugular involvement. Hemostatic dressing applied by officer on scene with partial effect. Trachea appears midline. No subcutaneous emphysema. Tachycardic and hypotensive.", teaching_points:"1. Neck wounds with pulsatile bleeding suggest major vascular injury — do NOT apply a circumferential bandage to the neck as this can compress the airway and contralateral carotid; apply direct manual pressure only to the wound itself. 2. Zone 1 (below thyroid), Zone 2 (thyroid to angle of jaw), and Zone 3 (above jaw) neck injuries all carry different surgical approaches — document the anatomical location precisely in your report and radio report." },
  { dispatch_line:"Medic 12, Big Daddy's Gentleman's Club — patron, 50s, chest pain and palpitations.", chief_complaint:"Chest pain with palpitations, possible cardiac", scene_description:"A male patron is seated at a table farthest from the stage. A server noticed him looking pale and clutching his chest and called 911. He says he has been having intermittent palpitations and chest discomfort for about 20 minutes. He also admits to cocaine use earlier in the evening.", patient_info:"51-year-old male, PMH: hypertension, takes amlodipine. Admits cocaine use 1 hour ago.", vitals:{bp:"188/116",hr:"148",rr:"22",spo2:"96%",gcs:"15",temp:"99.0°F"}, pertinent_findings:"Hypertensive and tachycardic. Chest pressure 6/10 without radiation. Diaphoretic. Cocaine use within past hour. Lung sounds clear. No JVD. Cocaine causes coronary vasospasm and can precipitate MI even in young patients.", teaching_points:"1. Cocaine-associated chest pain is a true cardiac emergency — cocaine causes coronary vasospasm, markedly elevated blood pressure, and tachycardia simultaneously creating ideal conditions for MI; treat as ACS and transport urgently. 2. Nitroglycerin is controversial in cocaine-induced chest pain and beta blockers are contraindicated — do not administer these medications without ALS medical direction; your role at the BLS level is oxygen, positioning, and rapid transport." },
  { dispatch_line:"Medic 12, Big Daddy's Gentleman's Club — employee, fall from stage, possible spinal injury.", chief_complaint:"Fall from elevated stage, back and neck pain", scene_description:"A performer fell backward off a 4-foot elevated stage during a performance. Several witnesses saw her land directly on her upper back and head. She is alert and talking but says she cannot feel her legs. She is lying on the floor where she fell and is very frightened.", patient_info:"28-year-old female, PMH: none.", vitals:{bp:"118/72",hr:"84",rr:"18",spo2:"99%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Alert and oriented. Reports she cannot feel her legs bilaterally and cannot move them to command. Upper extremity strength and sensation appears intact. No palpable deformity on cervical or thoracic spine. Mechanism and symptoms consistent with thoracic spinal cord injury.", teaching_points:"1. Neurogenic shock (hypotension and bradycardia in the setting of spinal cord injury) differs from hemorrhagic shock — the bradycardia is the distinguishing feature; a spinal cord injury patient who is hypotensive and bradycardic needs fluid resuscitation and rapid transport, not just volume. 2. Maintain strict spinal precautions with manual stabilization until properly packaged — one person maintains inline cervical stabilization at all times during patient movement; do not release until secured on a long board or scoop stretcher." },
],

bd_bar: [
  { dispatch_line:"Medic 12, Big Daddy's Tap Room, 370 Big Daddy Blvd — male, acute alcohol intoxication, unresponsive.", chief_complaint:"Unresponsive, acute alcohol poisoning", scene_description:"Bar staff called because a male patron stopped responding to stimulation at the bar. He is slumped forward on the bar with his head on his arms. He was reportedly drinking since opening at noon and is now unresponsive. His breathing is slow and irregular.", patient_info:"Approximately 45-year-old male, PMH: unknown, heavy alcohol odor.", vitals:{bp:"96/54",hr:"56",rr:"7",spo2:"84%",gcs:"6",temp:"96.2°F"}, pertinent_findings:"Unresponsive to voice, moans to sternal rub only. Respiratory depression with irregular pattern. SpO2 84% improving with jaw thrust. Pupils equal, sluggish. Blood glucose 62 mg/dL. Hypothermic at 96.2°F.", teaching_points:"1. Alcohol poisoning with respiratory depression is a true airway emergency — alcohol directly depresses the brainstem respiratory center; position airway, be ready to ventilate, and transport. 2. Always check a blood glucose in altered or unresponsive patients regardless of obvious intoxication — hypoglycemia is common in alcoholism and the treatment is simple; missing it can be fatal." },
  { dispatch_line:"Medic 12, Big Daddy's Tap Room — barfight, multiple patients, one with suspected broken ribs.", chief_complaint:"Blunt chest trauma, rib pain, shortness of breath", scene_description:"Police are on scene. Three people were involved in a fight. Your patient is a male sitting outside who took several kicks to the ribs while on the ground. He is alert but breathing is painful and shallow. He is guarding his left chest with both arms and will not take a deep breath.", patient_info:"40-year-old male, PMH: none.", vitals:{bp:"128/80",hr:"106",rr:"26 shallow",spo2:"93%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Severe left lateral chest wall tenderness with crepitus felt on palpation suggesting rib fractures. Breath sounds decreased on the left. Guarding significantly limits respiratory effort. SpO2 93% on room air. No tracheal deviation. Mechanism suggests multiple rib involvement.", teaching_points:"1. Multiple rib fractures cause a 'pain-splinting' cycle — pain causes shallow breathing, which leads to atelectasis and hypoxia, which worsens distress; O2 and a position of comfort that allows full tidal volume are your interventions. 2. If three or more adjacent ribs are each fractured in two places, paradoxical chest wall movement (flail chest) can develop — watch for a segment of the chest wall moving opposite to the rest with each breath, as this significantly impairs ventilation." },
  { dispatch_line:"Medic 12, Big Daddy's Tap Room — female customer, 60s, syncope in the restroom.", chief_complaint:"Syncope, found unresponsive on bathroom floor", scene_description:"A cleaning staff member found a female unresponsive on the bathroom floor. She has a pulse and is breathing. She is regaining consciousness as you arrive and is confused about where she is. No witnesses to the event. She has a bruise forming on her forehead from the fall.", patient_info:"61-year-old female, PMH: hypertension, atrial fibrillation, takes Eliquis.", vitals:{bp:"84/52",hr:"38 irregular",rr:"14",spo2:"96%",gcs:"13",temp:"98.2°F"}, pertinent_findings:"Profound bradycardia at 38 bpm with an irregular rhythm in a known afib patient. Markedly hypotensive. She is on an anticoagulant with a forehead contusion from the fall. No obvious source of bleeding externally. Cool, pale skin.", teaching_points:"1. Syncope with profound bradycardia in an afib patient raises concern for a cardiac arrhythmia or complete heart block — this is an ALS emergency; transport immediately and request ALS intercept while managing airway and positioning. 2. Anticoagulated patients who sustain head trauma from syncope are at high risk for intracranial hemorrhage — even with a mechanism that appears minor, Eliquis significantly elevates this risk; communicate anticoagulant use to the ER urgently." },
  { dispatch_line:"Medic 12, Big Daddy's Tap Room — male, 20s, severe allergic reaction, peanuts in bar snacks.", chief_complaint:"Anaphylaxis from peanut exposure", scene_description:"A 23-year-old male grabbed a handful of bar mix snacks without knowing they contained peanuts. Within 10 minutes he developed generalized hives, his throat tightened, and he told his friends he couldn't breathe. He is now in the parking lot sitting on the ground.", patient_info:"23-year-old male, PMH: severe peanut allergy, left his EpiPen at home.", vitals:{bp:"84/50",hr:"136",rr:"30",spo2:"90%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"Widespread urticaria, angioedema of lips and tongue, audible stridor. Hypotensive and tachycardic. SpO2 90% and falling. Patient is visibly frightened and says his throat is closing. No EpiPen available on scene.", teaching_points:"1. Anaphylaxis without a patient's EpiPen available requires EMT-administered epinephrine per your local protocol — know your scope of practice for epinephrine IM; do NOT wait for the patient to find their device or for ALS if the airway is closing. 2. Stridor indicates upper airway narrowing from angioedema — this can progress to complete obstruction rapidly; high-flow O2, epinephrine, positioning upright, and the fastest possible transport are all happening simultaneously." },
],

bd_motel: [
  { dispatch_line:"Medic 12, Big Daddy's Motor Inn, 99 Papa Drive — room 14, welfare check, occupant not seen for 2 days, possible overdose.", chief_complaint:"Unresponsive, found down, suspected overdose", scene_description:"Management opened room 14 after a neighbor reported hearing nothing for two days. A male is found on the bed unresponsive. The room smells of urine and body odor. Several empty pill bottles are on the nightstand. He has a weak pulse.", patient_info:"Approximately 38-year-old male, PMH: unknown, prescription bottles on nightstand for oxycodone and benzodiazepines.", vitals:{bp:"82/46",hr:"52",rr:"5",spo2:"76%",gcs:"4",temp:"94.2°F"}, pertinent_findings:"Profoundly unresponsive, hypothermic, in respiratory failure. Pinpoint pupils. Skin breakdown noted at pressure points suggesting prolonged immobility. Pill bottles empty — cannot determine original count.", teaching_points:"1. Combined opioid and benzodiazepine overdose causes synergistic respiratory depression and is more dangerous than either drug alone — naloxone addresses the opioid component but does not reverse benzodiazepine toxicity; even after naloxone, ventilatory support and transport are required. 2. Prolonged immobility from unconsciousness causes rhabdomyolysis and pressure injuries — communicate the estimated downtime to the ER as it significantly affects their evaluation and fluid management." },
  { dispatch_line:"Medic 12, Big Daddy's Motor Inn — room 8, male, hanging, found by wife.", chief_complaint:"Hanging, found by family, traumatic asphyxia", scene_description:"A female called 911 screaming. You arrive to find her husband in the bathroom, having been found hanging. He has been cut down and is on the floor. He has a weak pulse. There is a deep ligature mark around his neck and he is making agonal gasping sounds.", patient_info:"42-year-old male, PMH: depression, recently lost job.", vitals:{bp:"98/60",hr:"46",rr:"agonal",spo2:"72%",gcs:"4",temp:"97.8°F"}, pertinent_findings:"Deep circumferential ligature mark. Agonal respirations. Cervical spine injury possible from hanging mechanism. Profoundly bradycardic and hypoxic. Lips are cyanotic. Wife is extremely distraught in the doorway.", teaching_points:"1. Hanging causes a combination of cervical spine injury, airway obstruction from ligature, and hypoxic brain injury — maintain spinal precautions while aggressively managing the airway; these two priorities must happen simultaneously. 2. Airway management is the priority in hanging — the ligature mark indicates neck compression and potential laryngeal fracture; anticipate a difficult airway and have BVM ready; suction secretions as needed." },
  { dispatch_line:"Medic 12, Big Daddy's Motor Inn — room 22, female, 30s, difficulty breathing, chest pain, possible PE.", chief_complaint:"Sudden onset dyspnea and pleuritic chest pain", scene_description:"A 33-year-old female called the front desk saying she could not breathe. She is found sitting upright on the bed in obvious respiratory distress. She arrived yesterday after a 14-hour car trip. She has sharp chest pain that worsens with breathing and is extremely frightened.", patient_info:"33-year-old female, PMH: oral contraceptive use, 14-hour car ride yesterday.", vitals:{bp:"108/68",hr:"126",rr:"32",spo2:"90%",gcs:"15",temp:"99.2°F"}, pertinent_findings:"Tachycardic and tachypneic with pleuritic chest pain. SpO2 90%. Right calf is notably more swollen than the left and tender to palpation — suggesting DVT. OCP use and prolonged immobility are major risk factors for pulmonary embolism. No wheezing.", teaching_points:"1. The classic PE risk triad is prolonged immobility, hypercoagulable state (OCP use), and recent travel — this patient has all three; SpO2 of 90% with pleuritic chest pain in this context is a PE until proven otherwise. 2. There is no field treatment for PE beyond supportive care — high-flow O2, position of comfort, IV access if ALS is available, and the fastest possible transport to an ER capable of CT angiography and anticoagulation." },
  { dispatch_line:"Medic 12, Big Daddy's Motor Inn — room 31, child, 1 year old, unresponsive, possible SIDS.", chief_complaint:"Infant unresponsive, found in crib, pulseless", scene_description:"Parents called 911 when they found their 14-month-old unresponsive in the crib. The child was put to bed normally last night. She is cool to the touch, pulseless, and apneic. There is no obvious trauma. The parents are hysterical in the doorway.", patient_info:"14-month-old female, PMH: normal healthy infant, last well visit 2 months ago.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"91.2°F"}, pertinent_findings:"Pulseless and apneic. Cool to touch — temperature 91.2°F. Dependent lividity beginning on the back. Rigor mortis starting in the jaw. Findings suggest prolonged downtime inconsistent with survival.", teaching_points:"1. Signs incompatible with resuscitation (rigor mortis, dependent lividity, environmental temperature inconsistent with metabolic activity) allow withholding resuscitation per medical director protocol — know your local protocol; calling a pediatric death is one of the most difficult things in EMS. 2. Family support is as important as clinical care in these situations — designate one crew member to stay with the parents away from the patient, speak calmly and honestly, and coordinate early with law enforcement and social services as infant death requires investigation." },
],

bd_suites: [
  { dispatch_line:"Medic 12, Big Daddy Suites, 840 Crown St — room 205, male guest, severe allergic reaction.", chief_complaint:"Anaphylaxis, bee sting on hotel grounds", scene_description:"A male guest was stung multiple times by a swarm of bees near the outdoor pool. He came inside and told the front desk he felt sick, then rapidly deteriorated in the lobby. He is now on the lobby floor, barely responsive, with hives covering his trunk.", patient_info:"47-year-old male, PMH: no prior anaphylaxis, no known bee allergy.", vitals:{bp:"76/44",hr:"140",rr:"30",spo2:"88%",gcs:"11",temp:"98.8°F"}, pertinent_findings:"Anaphylactic shock. Multiple bee stings visible on arms and neck. Widespread urticaria. Angioedema developing at the lips. SpO2 88% and dropping. Profoundly hypotensive and tachycardic. Diminishing responsiveness.", teaching_points:"1. First-time anaphylaxis can be just as severe as reactions in patients with known allergies — a massive allergen load from multiple stings can cause immediate systemic anaphylaxis; epinephrine IM (per protocol), O2, and resuscitation position. 2. Anaphylactic shock with hypotension and decreasing LOC is a cardiovascular emergency as much as a respiratory one — epinephrine causes vasoconstriction reversing the distributive shock; positioning supine with legs elevated (if no respiratory distress) improves venous return." },
  { dispatch_line:"Medic 12, Big Daddy Suites — room 114, male guest, chest pain, called front desk.", chief_complaint:"Chest pain, left arm numbness, mid-50s", scene_description:"A hotel guest called the front desk saying he had chest pain. You find him sitting on the edge of the bed in business clothes. He arrived from out of state for a conference. He says the pain started during a stressful phone call. He is pale and looks worried.", patient_info:"54-year-old male, PMH: hypertension, dyslipidemia, takes atorvastatin — did not bring blood pressure medication.", vitals:{bp:"178/106",hr:"98",rr:"18",spo2:"96%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Substernal chest pressure 7/10 with left arm numbness. Diaphoretic. Hypertensive with significant cardiac risk factors. Has not taken his blood pressure medication in 2 days. Clear lung sounds. No JVD.", teaching_points:"1. Medication non-compliance is a significant precipitant of ACS — two missed doses of antihypertensives combined with acute stress can trigger hypertensive crisis and ACS simultaneously; treat as ACS regardless of the stressor. 2. ACS in a travelling patient means you may have limited medical history — ask specifically about cardiac medications, recent procedures, and family history; even incomplete information is better than none and should be documented and relayed to the ER." },
  { dispatch_line:"Medic 12, Big Daddy Suites — pool area, child, 8 years old, submersion injury.", chief_complaint:"Near-drowning, submersion injury", scene_description:"Hotel guests pulled an 8-year-old boy from the pool. He was found face down and unresponsive at the bottom of the shallow end. He had been swimming without supervision. He has a pulse but is coughing and vomiting water. He is alert but very confused.", patient_info:"8-year-old male, PMH: none, non-swimmer.", vitals:{bp:"100/62",hr:"128",rr:"28 with coughing",spo2:"88%",gcs:"12",temp:"96.8°F"}, pertinent_findings:"Post-submersion respiratory distress. Coughing and vomiting water. SpO2 88%. Tachycardic and tachypneic. Hypothermic at 96.8°F. Alert but confused. Lungs with coarse crackles bilaterally from aspiration.", teaching_points:"1. Near-drowning patients who appear to recover at the scene can deteriorate dramatically within hours from secondary drowning (delayed pulmonary edema) — all submersion victims, even those who appear well, must be transported for observation and monitoring. 2. Suction the airway aggressively but gently and position the child in the recovery position — aspiration of water causes lung injury and bronchospasm; high-flow O2 and warming are your primary treatments." },
  { dispatch_line:"Medic 12, Big Daddy Suites — room 308, female guest, 20s, difficulty breathing, asthma attack, no inhaler.", chief_complaint:"Severe asthma, no medications available", scene_description:"A female guest called the front desk barely able to speak. You find her in her room on the bed in tripod position. She came on a weekend trip and forgot her inhaler at home. She says she walked up three flights of stairs to avoid the elevator (it was broken) and triggered an attack.", patient_info:"22-year-old female, PMH: moderate persistent asthma, uses albuterol and budesonide.", vitals:{bp:"126/78",hr:"120",rr:"34",spo2:"90%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Severe bronchospasm with audible expiratory wheeze and prolonged expiration. Accessory muscle use with supraclavicular retractions. SpO2 90% and slowly declining. Cannot speak more than 3 words at a time. Last albuterol use was at home this morning.", teaching_points:"1. A severe asthma attack in a patient without their bronchodilator is immediately dangerous — high-flow O2 and BVM-assisted ventilation if SpO2 continues to decline; BVM ventilation in active bronchospasm requires slow, gentle breaths to prevent dynamic hyperinflation. 2. Know when to call for ALS — a patient with SpO2 declining despite positioning and O2 administration needs nebulized albuterol (ALS) and potentially magnesium sulfate; do not delay ALS intercept thinking the patient might improve." },
],

bd_fire: [
  { dispatch_line:"Medic 12, respond to Big Daddy Fire Station 1 — off-duty firefighter, 50s, chest pain in the apparatus bay.", chief_complaint:"Chest pain, diaphoresis in a firefighter", scene_description:"An off-duty firefighter came into the station to help with a gear issue and complained of chest pain to the on-duty crew. He is sitting on a bench in the apparatus bay. He is a large male, visibly pale and sweating, and appears uncomfortable.", patient_info:"52-year-old male, PMH: hypertension, GERD, heavy physical labor occupation.", vitals:{bp:"168/104",hr:"94",rr:"20",spo2:"95%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Firefighters are famously stoic and minimize symptoms — he rated the pain 4/10 and almost did not say anything. Substernal pressure with radiation to the left shoulder. Diaphoretic. Clear lungs. He initially attributed the pain to heartburn.", teaching_points:"1. Firefighters, police, and EMS personnel often downplay their own symptoms — treat the objective findings (diaphoresis, radiation, hypoxia) more than the subjective rating; a 52-year-old male firefighter with these symptoms is having an ACS until proven otherwise. 2. GERD and atypical presentations are common in male patients with ACS — do not allow a history of 'heartburn' to lower your clinical suspicion when the presentation includes diaphoresis and cardiovascular risk factors." },
  { dispatch_line:"Medic 12, Big Daddy Fire Station 1 — mutual aid, firefighter down, heat exhaustion during training drill.", chief_complaint:"Heat exhaustion during structural fire training", scene_description:"A firefighter collapsed during a live burn training exercise in full gear. Fellow firefighters removed his SCBA and gear. He is on the apparatus bay floor, conscious but confused, and soaked in sweat. Outside temperature is 95°F and he has been in gear for 45 minutes.", patient_info:"29-year-old male, PMH: none, 6 years in service.", vitals:{bp:"96/58",hr:"132",rr:"28",spo2:"97%",gcs:"13",temp:"104.6°F"}, pertinent_findings:"Core temperature 104.6°F. Confused and cannot state the date. Skin is hot and moist. Tachycardic and hypotensive. Muscle cramping in calves. No anhidrosis noted (still diaphoretic, which is a favorable sign versus classic heat stroke).", teaching_points:"1. A core temp above 104°F with CNS changes meets criteria for heat stroke, not just heat exhaustion — begin aggressive cooling immediately: ice packs to neck, axilla, and groin, wet sheets, fan if available, and cool the ambulance; do not wait for transport to begin cooling. 2. Firefighters in full structural gear are at extreme risk for heat illness due to encapsulation — their gear traps body heat completely; always take vitals including temperature during rehabilitation periods at training events and real incidents." },
  { dispatch_line:"Medic 12, Big Daddy Fire Station 1 — civilian, drove to station, 70s, possible stroke.", chief_complaint:"Civilian self-transport to fire station, stroke symptoms", scene_description:"An elderly man drove himself to the fire station because it was closer than the hospital. He came in saying his left arm felt strange and he was having trouble talking. On-duty firefighters called you immediately. He is sitting in the station lobby.", patient_info:"71-year-old male, PMH: hypertension, diabetes, takes metformin and amlodipine.", vitals:{bp:"202/118",hr:"82",rr:"16",spo2:"97%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"FAST positive — left facial droop, left arm weakness with drift, moderate dysarthria (slurred speech). Last known well is when he left home, approximately 35 minutes ago. BG 134 mg/dL. No trauma from driving.", teaching_points:"1. This patient's decision to drive himself was dangerous but gives you an important last known well time — document precisely that he drove himself and appeared neurologically intact enough to operate a vehicle 35 minutes prior; this information affects tPA eligibility calculations. 2. Driving with stroke symptoms puts the public at risk and is a common EMT teaching moment — document the decision to self-transport without judgment and focus on the medical emergency; the social and legal discussion is for later." },
  { dispatch_line:"Medic 12, Big Daddy Fire Station 1 — training injury, probie, 22 years old, fell from ladder during training.", chief_complaint:"Fall from ladder, leg pain and back pain", scene_description:"A probationary firefighter fell from the third rung of a ground ladder during ladder training. He landed on the apparatus bay floor on his feet and then fell backward onto his back. He is alert and talking but has severe right ankle pain and moderate low back pain.", patient_info:"22-year-old male, PMH: none, probationary firefighter.", vitals:{bp:"128/78",hr:"96",rr:"18",spo2:"99%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Right ankle is swollen and tender with limited ROM — fracture likely. Low back pain 6/10 with midline spinous process tenderness at L3-L4. Leg strength and sensation intact bilaterally. No obvious upper extremity or head injury. Mechanism included axial loading through both lower extremities.", teaching_points:"1. Axial loading through the feet (landing on your feet from a fall) commonly causes calcaneus (heel) fractures AND lumbar compression fractures simultaneously — always assess the entire spine in a jumping or falling mechanism regardless of where the patient points to pain. 2. Distracting injuries like an obvious ankle fracture can cause patients and providers to miss a concurrent spinal injury — complete your spinal assessment systematically before fixating on the most obvious injury." },
],

bd_police: [
  { dispatch_line:"Medic 12, respond to Big Daddy PD, 420 Big Daddy Blvd — prisoner in custody, chest pain.", chief_complaint:"Prisoner with chest pain after use of force", scene_description:"Police called EMS after a male prisoner complained of chest pain following a struggle during arrest. He is handcuffed and seated in the booking area. He has visible bruising to his torso and face from the altercation. He is breathing rapidly and says his chest hurts to breathe.", patient_info:"38-year-old male, PMH: unknown, in police custody.", vitals:{bp:"148/90",hr:"116",rr:"26",spo2:"93%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Left lateral chest wall tenderness with splinting. Decreased breath sounds on the left. SpO2 93% in a tachycardic, tachypneic patient with visible rib trauma. Mechanism includes physical struggle and blunt force to the chest.", teaching_points:"1. A prisoner or person in custody is still your patient — provide the same standard of care you would for any other patient; pain assessment, vital signs, and transport decisions are clinical not custodial. 2. Decreased breath sounds plus chest wall trauma plus low SpO2 after trauma requires consideration of pneumothorax — monitor closely for deterioration and communicate your findings clearly to the ER; these patients can decompensate rapidly in the back of the unit." },
  { dispatch_line:"Medic 12, Big Daddy PD — officer involved in crash during pursuit, airbag deployment, chest injury.", chief_complaint:"Airbag deployment, chest pain and shortness of breath", scene_description:"A police officer crashed his cruiser during a pursuit. Airbags deployed. He is alert and out of the vehicle, leaning against the door. He is in full uniform and vest. He says his chest is burning and it hurts to take a deep breath. He refused to wait for EMS initially.", patient_info:"34-year-old male police officer, PMH: none.", vitals:{bp:"132/84",hr:"102",rr:"22",spo2:"96%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Central anterior chest tenderness consistent with airbag/seatbelt injury. Body armor was worn. Decreased breath sounds in right base. SpO2 96% and trending down. No steering wheel deformity. Airbag abrasion on both forearms and face.", teaching_points:"1. Body armor can both protect and injure — it disperses impact broadly across the anterior chest, which can cause sternum fractures and bilateral rib injuries while preventing penetrating trauma; assess under the armor when possible and have the officer remove the vest. 2. Airbag deployment causes a predictable injury pattern — airbag abrasions to arms and face, steering column impact to sternum, and seatbelt injuries to clavicle and shoulder; systematically assess each of these areas." },
  { dispatch_line:"Medic 12, Big Daddy PD — employee in records room, unresponsive, found by coworker.", chief_complaint:"Employee found unresponsive at desk", scene_description:"A civilian records clerk is found slumped over her desk. A coworker says she had complained of a severe headache all morning and then stopped responding. She is pulseless. Her chair and desk are undisturbed — no evidence of trauma or fall.", patient_info:"48-year-old female, PMH: hypertension, headache all morning per coworkers.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Pulseless and apneic. Non-traumatic cardiac arrest in a 48-year-old with a prodrome of severe headache suggesting possible intracranial hemorrhage as the cause. Begin CPR immediately.", teaching_points:"1. Non-traumatic cardiac arrest with a preceding severe headache suggests subarachnoid hemorrhage as the cause — the 'thunderclap headache' preceding collapse is a classic presentation; communicate this history to the ER as it affects post-resuscitation imaging priorities. 2. Begin high-quality CPR immediately — regardless of suspected cause, cardiac arrest management is the same at the BLS level; compressions, airway, AED, and transport." },
  { dispatch_line:"Medic 12, Big Daddy PD — holding cell, male prisoner, found unresponsive, suspected overdose.", chief_complaint:"Prisoner unresponsive in holding cell, overdose", scene_description:"Officers found a male prisoner unresponsive in a holding cell. He was processed 2 hours ago and must have had drugs concealed on his person. He is on the floor with slow, irregular breathing. Officers have already opened the cell.", patient_info:"26-year-old male, PMH: unknown, drugs concealed on person.", vitals:{bp:"84/50",hr:"52",rr:"5",spo2:"78%",gcs:"4",temp:"97.2°F"}, pertinent_findings:"Respiratory failure with agonal breathing. Pinpoint pupils bilaterally. Pulse is slow and thready. No visible injuries. SpO2 78%. Multiple small bags found near patient — suspected fentanyl.", teaching_points:"1. Body-pack or body-stuffing scenarios (ingested drug packages) present differently than typical OD — packages can rupture releasing massive doses; standard naloxone may be insufficient and repeated dosing may be required; communicate this mechanism to the ER. 2. Scene safety in a jail or holding environment is different from street calls — law enforcement controls movement and access; communicate with officers before moving the patient and ensure they remain present during treatment." },
],

bd_school: [
  { dispatch_line:"Medic 12, Big Daddy High School, 60 Papa Drive — student, 16 years old, seizure on the football field.", chief_complaint:"Seizure during football practice", scene_description:"Football coaches called 911 when a player had a seizure on the field during afternoon practice. The player is post-ictal on the field. He is breathing on his own, confused, and moving all extremities. His helmet is still on and the coach is holding his head.", patient_info:"16-year-old male, PMH: no seizure history, football player.", vitals:{bp:"128/80",hr:"110",rr:"16",spo2:"97%",gcs:"12",temp:"99.8°F"}, pertinent_findings:"Post-ictal state following first witnessed seizure in a 16-year-old athlete. Helmet still in place — do not remove without proper protocol. Slightly elevated temp. No known seizure disorder. Possible heat contribution given outdoor practice.", teaching_points:"1. Helmets should NOT be removed on the field in the same way you would not remove a motorcycle helmet — in football players, remove the face mask and leave the helmet in place unless airway access requires full removal, and if removed, do so in coordination with spinal precautions. 2. New onset seizure in a teenage athlete during heat exposure has a broad differential (heat illness, hyponatremia from overhydration, stimulant use, undiagnosed epilepsy, cardiac arrhythmia) — transport all first-time seizures for full workup." },
  { dispatch_line:"Medic 12, Big Daddy High School — teacher, 40s, allergic reaction in the classroom, epinephrine given by school nurse.", chief_complaint:"Anaphylaxis, epinephrine administered by school nurse", scene_description:"A teacher had an anaphylactic reaction from an unknown allergen in her classroom. The school nurse responded and administered epinephrine from the school's supply. The teacher is now in the nurse's office. She appears improved but is still tachycardic and has residual hives.", patient_info:"44-year-old female, PMH: no known allergies.", vitals:{bp:"112/70",hr:"118",rr:"20",spo2:"96%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Residual urticaria on trunk and arms. Mild bronchospasm with scattered wheeze. Hemodynamically improving since epinephrine. She does not know what triggered the reaction. First anaphylaxis ever. Epinephrine given 8 minutes ago.", teaching_points:"1. Epinephrine for anaphylaxis has a short duration of action (15-20 minutes) and biphasic reactions occur in up to 20% of cases — even a patient who looks much better after epinephrine requires transport and observation for at least 4-6 hours; never refuse transport after anaphylaxis. 2. A patient with a first-time anaphylaxis has no established epinephrine prescription — part of your handoff report to the ER should note that this patient needs allergy referral and an EpiPen prescription for future events." },
  { dispatch_line:"Medic 12, Big Daddy High School — student, 14 years old, found unresponsive in the bathroom, possible overdose.", chief_complaint:"Teenage student unresponsive, suspected fentanyl", scene_description:"A student was found unresponsive on the floor of the boys' bathroom. A student ran to get a teacher. The school resource officer is on scene. The student has very slow breathing and a small folded paper packet is near his hand. The SRO has already called for the principal.", patient_info:"14-year-old male, PMH: unknown, HIPAA limited but parents notified.", vitals:{bp:"88/52",hr:"58",rr:"4",spo2:"76%",gcs:"4",temp:"97.6°F"}, pertinent_findings:"Critically ill adolescent with profound respiratory depression. Pinpoint pupils. SpO2 76% on room air. Suspected fentanyl — small quantity of powder in folded paper. Bradycardic. Lips cyanotic.", teaching_points:"1. Fentanyl is 50-100 times more potent than morphine and a very small amount can cause fatal respiratory depression in a non-tolerant teenager — administer naloxone per protocol immediately and ventilate with BVM; multiple doses may be required due to fentanyl's potency relative to standard naloxone dosing. 2. In a school setting, scene management involves multiple agencies (school admin, SRO, parents, CPS) — stay focused on patient care and designate one person to communicate with non-medical personnel; protect patient confidentiality while also communicating safety concerns per your duty to warn protocols." },
  { dispatch_line:"Medic 12, Big Daddy High School — cafeteria, student, 15 years old, choking on food.", chief_complaint:"Choking student, partial obstruction clearing", scene_description:"A 15-year-old student was eating lunch when she began choking on a large piece of food. A lunch monitor performed several abdominal thrusts and the obstruction partially cleared — she can now cough but weakly and cannot speak clearly. Her SpO2 is dropping.", patient_info:"15-year-old female, PMH: none.", vitals:{bp:"118/72",hr:"118",rr:"labored cough",spo2:"88%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Partial airway obstruction after unsuccessful self-clearance and partial response to abdominal thrusts. Weak, ineffective cough. Can barely speak. SpO2 88% and declining. No stridor but clearly cannot move adequate air.", teaching_points:"1. A partial obstruction that fails to clear with coughing and abdominal thrusts and has declining SpO2 is becoming a complete obstruction — continue back blows and abdominal thrusts and prepare for potential airway management if the patient loses consciousness. 2. If a choking patient loses consciousness, begin CPR — with each ventilation attempt, look into the airway for the visible object and remove it only if you can clearly see it; chest compressions in an unconscious choking patient can help dislodge the object." },
],

bd_church: [
  { dispatch_line:"Medic 12, Big Daddy's House of Grace, 600 Throne Ave — elderly male, cardiac arrest during Sunday service.", chief_complaint:"Cardiac arrest in the church, CPR in progress", scene_description:"A large Sunday congregation is parting to let you through. An elderly male collapsed in his pew. A nurse in the congregation is doing CPR. There is an AED in the church hallway. The cardiac arrest occurred approximately 4 minutes ago.", patient_info:"78-year-old male, PMH: unknown per wife, 'heart problems' she says.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Pulseless and apneic with trained bystander CPR in progress. AED available in hallway. Large crowd present. Wife at bedside extremely distraught. Estimated downtime 4 minutes with CPR.", teaching_points:"1. Crowd control in a church or public space is a real operational challenge — designate someone immediately to manage bystanders and create a work space; you cannot run an effective resuscitation in a crowd. 2. High-quality CPR and early defibrillation are your only evidence-based interventions at the BLS level — communicate clearly, work as a team, minimize interruptions, and use the AED as fast as possible." },
  { dispatch_line:"Medic 12, Big Daddy's House of Grace — elderly female, 80s, hip pain after kneeling in the pew, unable to stand.", chief_complaint:"Hip pain after kneeling, unable to bear weight", scene_description:"An elderly woman was kneeling in prayer when she heard a pop in her left hip and experienced sudden, severe pain. She cannot stand and is sitting in the pew with her left leg externally rotated. The congregation gathers around. She is alert and her pain is severe.", patient_info:"82-year-old female, PMH: osteoporosis, atrial fibrillation, takes warfarin.", vitals:{bp:"152/88",hr:"92 irregular",rr:"18",spo2:"97%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Left lower extremity externally rotated and shortened. Severe groin and hip pain with any movement. Distal CSM intact. On anticoagulation. Low-energy mechanism (kneeling) is classic for pathologic or osteoporotic hip fracture.", teaching_points:"1. A hip fracture from a low-energy mechanism (kneeling, rolling over in bed) in an elderly osteoporotic patient is a pathologic fracture — the bone broke due to its own weakness before significant force was applied; this does not change immobilization management but is important clinical context. 2. Internal blood loss from a hip fracture can be 500mL to 1.5 liters into the pelvis and thigh — an elderly patient on warfarin is at even higher risk of significant hemorrhage; monitor for shock signs even when the patient appears stable initially." },
  { dispatch_line:"Medic 12, Big Daddy's House of Grace — child, 6 years old, febrile seizure during children's program.", chief_complaint:"Pediatric febrile seizure, now post-ictal", scene_description:"A 6-year-old boy had a seizure during the children's Bible program. The episode lasted approximately 90 seconds and stopped on its own. He is now post-ictal and lying on a cot in the children's area. His forehead is hot. His parents are panicked.", patient_info:"6-year-old male, PMH: ear infection diagnosed 2 days ago, on amoxicillin.", vitals:{bp:"108/64",hr:"128",rr:"22",spo2:"97%",gcs:"12",temp:"103.8°F"}, pertinent_findings:"Post-ictal 6-year-old with fever of 103.8°F. Currently confused but improving. Airway patent and breathing adequately. No focal neurological deficits. No prior seizure history. Currently on antibiotics for otitis media.", teaching_points:"1. A febrile seizure in a child aged 6 months to 5 years is usually benign and self-limited — however, this child is 6 years old (slightly outside the typical febrile seizure window) making a full workup necessary; transport all first-time pediatric seizures regardless of fever. 2. Cooling measures for fever (cool cloths, removing excess clothing) are supportive and can help prevent a repeat febrile seizure — do not use ice baths or cold water, which can cause shivering that raises core temp; transport for evaluation." },
  { dispatch_line:"Medic 12, Big Daddy's House of Grace — female, 30s, syncope at the pulpit during a ceremony.", chief_complaint:"Syncope, fell from the pulpit, head strike", scene_description:"A young female minister fainted while leading a ceremony and fell forward off the elevated pulpit platform. She struck her chin and chest on the platform edge on the way down. She is on the floor with a congregation member supporting her head. She is regaining consciousness.", patient_info:"34-year-old female, PMH: none, 8 months pregnant.", vitals:{bp:"88/52",hr:"108",rr:"20",spo2:"98%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"8-month (32 week) pregnant patient with syncope and fall. Chin laceration with controlled bleeding. Complains of abdominal pain since falling. Uterus is at the fundal height for 32 weeks. She fell forward — direct anterior abdominal impact on the platform edge.", teaching_points:"1. Direct trauma to the gravid uterus is an obstetric emergency — placental abruption presents with abdominal pain, uterine rigidity, and potentially concealed hemorrhage that can cause rapid deterioration; transport emergently to an OB-capable facility. 2. Syncope in a third-trimester patient is often positional (aortocaval compression in supine position) — transport in left lateral decubitus position, which may be both therapeutic and diagnostic; if BP improves with position change, supine hypotension was likely the cause." },
],

bd_park: [
  { dispatch_line:"Medic 12, Deron's Dreamland Park — 34-year-old male, fall from bench, wrist injury, FOOSH mechanism.", chief_complaint:"Distal radius fracture, pain management, splinting", scene_description:"A male fell off a park bench and caught himself with his outstretched right hand. His wrist is visibly deformed with immediate swelling. He is in severe pain rated 9/10 and cannot move the wrist. A group of joggers stopped to help.", patient_info:"34-year-old male, PMH: none. No medications.", vitals:{bp:"132/84",hr:"98",rr:"16",spo2:"99%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Distal radius deformity — Colles fracture. Point tenderness at distal radius. Distal CSM intact — fingers warm with normal sensation and movement. No open wound. Pain 9/10.", teaching_points:"1. Assess distal CSM before and after every splint application — circulation, sensation, and motor function must be documented before and after splinting; any change after splinting requires immediate loosening and reassessment. 2. A posterior long arm splint with the wrist in slight extension and the forearm in neutral position is the appropriate field splint for a Colles fracture — pad bony prominences and apply with gentle traction." },
  { dispatch_line:"Medic 12, Deron's Dreamland Park — 43-year-old female jogger, near-syncope, heat exhaustion.", chief_complaint:"Heat exhaustion, near-syncope, active cooling needed", scene_description:"A 43-year-old female jogger nearly lost consciousness on her third lap and was helped to a bench by a bystander. She is hot, flushed, and moist with a temperature of 102.6°F. She is alert and oriented but weak. She brought no water.", patient_info:"43-year-old female, PMH: hypertension on hydrochlorothiazide.", vitals:{bp:"96/58",hr:"118",rr:"22",spo2:"98%",gcs:"15",temp:"102.6°F"}, pertinent_findings:"Heat exhaustion — hot moist skin, near-syncope, tachycardic, mildly hypotensive. Temperature 102.6°F. Diuretic use worsening dehydration. Alert and oriented. No neurological deficits.", teaching_points:"1. Heat exhaustion vs heat stroke — key distinction is mental status; heat exhaustion patients are alert and oriented with hot moist skin; heat stroke patients have altered mental status and hot DRY skin; this patient's intact mental status confirms heat exhaustion at this time. 2. Move to shade, remove excess clothing, apply cool wet cloths to neck and axilla, oral fluids if the patient is alert and able to swallow safely — all are appropriate BLS interventions for heat exhaustion." },
  { dispatch_line:"Medic 12, Deron's Dreamland Park — 8-year-old male, stick to eye, crying, cannot open eye.", chief_complaint:"Eye injury from stick, possible globe injury", scene_description:"An 8-year-old was running in the wooded section of the park and a branch struck his right eye. He is crying and holding his hand over his eye. He cannot open it due to pain. His right eye is red with excessive tearing. His parent is present and very concerned.", patient_info:"8-year-old male, PMH: none.", vitals:{bp:"108/66",hr:"108",rr:"18",spo2:"99%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Significant right eye pain with inability to open the eye. Subconjunctival hemorrhage visible when the eye is gently examined. Excessive tearing. Globe rupture must be considered with this mechanism.", teaching_points:"1. Rigid eye shield — never apply direct pressure to a suspected globe rupture; apply a rigid shield such as a Fox eye shield or a paper cup taped around the orbit without touching the eye; patch the uninjured eye as well to reduce sympathetic eye movement. 2. Keep the patient calm and upright — straining, crying, bending over, or Valsalva significantly increases intraocular pressure and can extrude vitreous through a globe rupture; reassure the child and keep them still during transport." },
  { dispatch_line:"Medic 12, Deron's Dreamland Park — 76-year-old male, tripped on uneven pavement, hip pain, cannot stand.", chief_complaint:"Hip fracture, cannot bear weight, pain management and splinting", scene_description:"An elderly male tripped on an uneven paving stone on the walking path and fell on his right side. His right leg is externally rotated and shortened. He is in severe pain rated 9/10 and cannot get up despite two bystanders attempting to help him. He is on warfarin.", patient_info:"76-year-old male, PMH: osteoporosis, atrial fibrillation. Takes warfarin and metoprolol.", vitals:{bp:"152/88",hr:"84 irregular",rr:"18",spo2:"96%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Classic hip fracture presentation — right leg externally rotated and shortened. Point tenderness over right hip. Pain 9/10 with any movement. Distal CSM intact. Anticoagulated on warfarin.", teaching_points:"1. Do not attempt to straighten a hip fracture in the field — immobilize the patient in the position of comfort with padding under the fractured limb; traction splints are contraindicated for hip fractures (only used for mid-shaft femur fractures); a scoop stretcher or long board with padding is the appropriate device. 2. Communicate anticoagulant use to the receiving facility — warfarin significantly increases the risk of hemorrhage at the fracture site and affects surgical planning; the ER must know the anticoagulant name, dose, and last dose time immediately upon arrival." },
],

bd_mhp: [
  { dispatch_line:"Medic 12, Big Daddy's Mobile Home Park, Lot 14 — male, 50s, difficulty breathing, wife called.", chief_complaint:"Difficulty breathing, COPD exacerbation, O2 concentrator unplugged", scene_description:"A narrow gravel lane leads to a single-wide trailer. A heavyset male is in a recliner in obvious respiratory distress. The home is cluttered and smoky. A portable O2 concentrator sits in the corner unplugged. His wife says he has been getting worse all day.", patient_info:"54-year-old male, PMH: COPD, CHF, hypertension, smoker x35 years.", vitals:{bp:"158/96",hr:"108",rr:"28",spo2:"84%",gcs:"15",temp:"99.2°F"}, pertinent_findings:"Severe accessory muscle use and tripod positioning. Bilateral expiratory wheeze with prolonged expiration. SpO2 84% on room air. O2 concentrator was unplugged — patient has been without supplemental O2 for unknown duration. Barrel chest consistent with severe COPD.", teaching_points:"1. Scene size-up in mobile home calls includes assessing access and egress — narrow lanes, steps, and tight interiors require early planning for stretcher placement; request additional resources early if needed for patient movement. 2. Always check home oxygen equipment — an unplugged or malfunctioning concentrator is a common and preventable cause of COPD exacerbation; document equipment status and communicate to the receiving facility." },
  { dispatch_line:"Medic 12, Big Daddy's Mobile Home Park, Lot 22 — welfare check, elderly female, not seen in 3 days.", chief_complaint:"Found down x3 days, unresponsive, hypoglycemia and hyperthermia", scene_description:"A neighbor called when mail piled up and the elderly resident didn't respond to knocking for 3 days. A 78-year-old female is found on the bathroom floor unresponsive. The home is very warm. She has signs of prolonged immobility including skin breakdown.", patient_info:"78-year-old female, PMH: diabetes, hypertension, lives alone.", vitals:{bp:"88/52",hr:"112",rr:"10",spo2:"90%",gcs:"6",temp:"103.8°F"}, pertinent_findings:"GCS 6. Febrile at 103.8°F. Skin breakdown at sacrum from prolonged immobility. Dry mucous membranes. BG 42 mg/dL critically low. Dehydrated throughout. Signs of prolonged downtime.", teaching_points:"1. Welfare check calls require thorough scene assessment — signs of prolonged downtime (mail accumulation, food left out, skin breakdown, incontinence) help estimate how long the patient has been down and guide clinical urgency. 2. Always check blood glucose in any unresponsive patient — hypoglycemia is a primary and easily treated contributor to altered mental status; this patient's BG of 42 requires immediate intervention." },
  { dispatch_line:"Medic 12, Big Daddy's Mobile Home Park, Lot 7 — 4-year-old, possible ingestion, mother's medications accessed.", chief_complaint:"Pediatric ingestion, opioid toxidrome, respiratory depression", scene_description:"A 4-year-old boy is sitting on the couch staring blankly after his mother found him in the bedroom where she keeps her medications. Several bottles were opened. The child is responsive but lethargic and not speaking. Mother's medications include oxycodone, alprazolam, and metformin.", patient_info:"4-year-old male, PMH: none. Weight approximately 16kg.", vitals:{bp:"88/54",hr:"62",rr:"14",spo2:"94%",gcs:"12",temp:"97.8°F"}, pertinent_findings:"Bradycardic with slow respirations and reduced GCS. Pupils constricted bilaterally. Lethargic and slow to respond. Opioid and benzodiazepine ingestion suspected given available medications and presentation.", teaching_points:"1. In any pediatric ingestion bring ALL medication bottles to the hospital — the ER and poison control need every possible substance; do not rely on parent memory; gather all bottles from the area where the child was found. 2. Bradycardia and pinpoint pupils in a child after suspected ingestion is an opioid toxidrome — administer naloxone per your protocol and be prepared to manage the airway; opioid ingestion in small children can cause rapid respiratory failure." },
  { dispatch_line:"Medic 12, Big Daddy's Mobile Home Park, Lot 31 — domestic dispute, female patient, facial trauma and arm injury.", chief_complaint:"Domestic violence, facial trauma, forearm fracture", scene_description:"Police have secured the scene. A 28-year-old female is on the front steps with visible bruising to the left side of her face. She is holding her right arm against her body and cannot move it without severe pain. She is 6 weeks postpartum. She says this has happened before.", patient_info:"28-year-old female, PMH: none. 6 weeks postpartum.", vitals:{bp:"136/88",hr:"104",rr:"18",spo2:"99%",gcs:"15",temp:"98.4°F"}, pertinent_findings:"Periorbital hematoma and nasal swelling. Right forearm deformity suggesting fracture — distal CSM intact. Tachycardic from pain and fear. She is fearful and keeps watching the police. A 2-year-old child is inside.", teaching_points:"1. Domestic violence is a mandatory reporting situation — document all injuries objectively with precise descriptions; your PCR may be used as legal evidence; photograph injuries if your protocol allows and the patient consents. 2. A postpartum patient in a domestic violence situation has additional risk factors — communicate to the ER that there is a young child in the home so social services can be notified appropriately." },
],

bd_nursing: [
  { dispatch_line:"Medic 12, Grand-daddy's Nursing and Rehab — room 12, male resident, acute change in mental status from baseline.", chief_complaint:"Acute AMS from baseline, sepsis suspected, UTI source", scene_description:"A 79-year-old male who is normally alert and oriented has become suddenly confused and combative over the last 2 hours. Staff say this is very unlike him. His nurse hands you a 14-medication list and says his urine has been cloudy and strong-smelling since yesterday.", patient_info:"79-year-old male, PMH: hypertension, Type 2 DM, atrial fibrillation. Takes warfarin, metoprolol, lisinopril and 11 others.", vitals:{bp:"168/102",hr:"92 irregular",rr:"18",spo2:"94%",gcs:"12",temp:"101.6°F"}, pertinent_findings:"Acute change in mental status from a normally alert baseline. Febrile 101.6°F. SpO2 94%. Urinalysis by staff shows cloudy urine with strong odor. BG 182. Afib rhythm on monitor. Anticoagulated on warfarin.", teaching_points:"1. Acute change from baseline mental status in a nursing home resident is a medical emergency — always establish the patient's baseline before judging their current status; an acute change from a previously alert person always requires evaluation even if the current GCS seems acceptable. 2. The nursing home staff are your best resource — the charge nurse knows the patient's baseline, medications, allergies, DNR status, and recent changes; gather this information rapidly and bring the medication list and any recent labs to the hospital." },
  { dispatch_line:"Medic 12, Grand-daddy's Nursing and Rehab — room 24, 84-year-old female, fall from bed, hip fracture, DNR on file.", chief_complaint:"Hip fracture, severe pain, DNR confirmed, anticoagulated", scene_description:"An 84-year-old female with moderate dementia was found on the floor beside her bed during morning rounds. She cannot recall falling. She is in significant pain and cannot move her right leg. A valid DNR is on file and confirmed. She is on Eliquis for atrial fibrillation.", patient_info:"84-year-old female, PMH: osteoporosis, afib, moderate dementia. Takes Eliquis, donepezil, memantine.", vitals:{bp:"144/88",hr:"86 irregular",rr:"16",spo2:"97%",gcs:"14",temp:"98.2°F"}, pertinent_findings:"Right leg externally rotated and shortened — classic hip fracture. Pain severe with any movement. DNR confirmed with document on file. On Eliquis — bleeding risk elevated. Behavioral pain cues: grimacing, guarding, resistance to movement.", teaching_points:"1. A DNR order means do not resuscitate — it does NOT mean do not treat; this patient still receives full treatment including pain management, splinting, IV access, and transport to the hospital; clarify with staff exactly what the DNR covers before transport. 2. Pain assessment in dementia patients requires behavioral observation — facial grimacing, guarding, moaning, and resistance to movement all indicate pain in a patient who cannot self-report; treat behavioral pain signs as seriously as a verbal pain complaint." },
  { dispatch_line:"Medic 12, Grand-daddy's Nursing and Rehab — room 8, 72-year-old male, respiratory distress after eating, aspiration suspected.", chief_complaint:"Aspiration after eating, SpO2 86%, DNI order on file", scene_description:"A 72-year-old male with stroke-related dysphagia developed respiratory distress during lunch. Staff say he was eating pureed food when he began coughing violently and now cannot breathe adequately. He has a known swallowing impairment from his CVA and a DNI order on file.", patient_info:"72-year-old male, PMH: CVA x2 years with residual dysphagia, hypertension, COPD. DNI order confirmed.", vitals:{bp:"148/92",hr:"118",rr:"34",spo2:"86%",gcs:"13",temp:"99.8°F"}, pertinent_findings:"Respiratory distress with audible gurgling and coarse crackles in right lower lobe. SpO2 86% with supplemental O2. Food particles visible in oropharynx. Febrile suggesting early aspiration pneumonia. DNI order confirmed by staff and documentation.", teaching_points:"1. A DNI order prohibits endotracheal intubation — suction, positioning, supplemental O2, and BVM ventilation as a bridge are all appropriate; RSI and placement of an ETT are not; confirm DNI status and document your confirmation before making any airway decisions. 2. Suctioning is always appropriate regardless of DNR or DNI status — removing aspirated material from the oropharynx is supportive care; use a yankauer to clear visible material and position the patient laterally to prevent further aspiration." },
  { dispatch_line:"Medic 12, Grand-daddy's Nursing and Rehab — room 19, 86-year-old female, cardiac arrest, staff performing CPR, DNR being located.", chief_complaint:"Cardiac arrest, CPR in progress, DNR document being located", scene_description:"Staff are performing CPR on an 86-year-old female found unresponsive in her room. You arrive to find two CNAs doing compressions. The charge nurse is frantically looking for the DNR paperwork. Staff believe there is a DNR but cannot immediately produce the physical document.", patient_info:"86-year-old female, PMH: end-stage CHF, COPD, dementia. Recent hospice evaluation per staff.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Pulseless and apneic. CPR in progress. Valid DNR not yet located. Staff verbally confirm they believe a DNR exists. Charge nurse still searching for the physical document.", teaching_points:"1. If a valid DNR cannot be immediately produced you must continue resuscitation — in most states a DNR must be a physical signed document present on scene; verbal statements from staff are not legally sufficient to withhold resuscitation; continue CPR while the document is being located. 2. Once a valid DNR is confirmed stop resuscitation per your protocol — document the time CPR was stopped, who confirmed the DNR, the document number, and your medical director notification; this documentation protects you legally and ensures appropriate follow-up." },
],

bd_estates: [
  { dispatch_line:"Medic 12, respond to 142 Estates Drive, Big Daddy Estates — 72-year-old male, difficulty breathing, family called.", chief_complaint:"Acute dyspnea, bilateral rales, suspected CHF exacerbation", scene_description:"You arrive to a well-kept ranch home. A 72-year-old male is found sitting upright in a recliner in obvious respiratory distress. His wife says he has been short of breath for two days and woke up last night unable to breathe lying flat. Three pillows are stacked behind him on the bed.", patient_info:"72-year-old male, PMH: CHF, hypertension, atrial fibrillation. Takes furosemide, lisinopril, carvedilol, digoxin.", vitals:{bp:"188/110",hr:"98 irregular",rr:"28",spo2:"88%",gcs:"15",temp:"98.2°F"}, pertinent_findings:"Bilateral crackles to mid-lung fields. JVD present at 45 degrees. Pitting edema bilateral ankles to mid-calf. Patient says he has been gaining weight — shoes don't fit. Cannot complete a full sentence without stopping to breathe. Orthopnea noted.", teaching_points:"1. Classic signs of CHF exacerbation include orthopnea, JVD, bilateral rales, and peripheral edema — position the patient upright (legs down to reduce preload), apply high-flow O2 to maintain SpO2 above 94%, and transport rapidly without laying the patient flat. 2. Do not withhold oxygen from a CHF patient with SpO2 of 88% due to concerns about hypoxic drive — the hypoxic drive theory applies to COPD patients with chronic CO2 retention, not CHF; this patient needs O2 now." },
  { dispatch_line:"Medic 12, 87 Crown Estates Court — unresponsive 4-year-old, mother hysterical, possible seizure.", chief_complaint:"Pediatric febrile seizure, postictal, fever 103.8°F", scene_description:"You arrive to find a terrified mother holding a limp 4-year-old boy on the kitchen floor. She says he had a convulsive seizure lasting about 90 seconds and is now unresponsive. He felt very hot before it started. He is breathing on his own but will not wake up.", patient_info:"4-year-old male, PMH: one prior febrile seizure at age 2. No seizure medications.", vitals:{bp:"not obtained",hr:"148",rr:"22",spo2:"97%",gcs:"9",temp:"103.8°F"}, pertinent_findings:"Postictal child — responds to painful stimuli only. Skin hot and flushed. No active seizure activity. Muscle tone flaccid. No head trauma reported. Mom confirms he was sick with a fever all day. No fever-reducing medication given.", teaching_points:"1. A febrile seizure in a child 6 months to 6 years with a fever is the most common type of childhood seizure — if the child is postictal but breathing and no longer actively seizing, airway management and transport are your priorities; do not aggressively stimulate the patient during the postictal phase. 2. Document the duration of seizure activity precisely — a seizure lasting more than 5 minutes is status epilepticus and changes your management; the mother reported 90 seconds which is within the febrile seizure norm, but always verify and document." },
  { dispatch_line:"Medic 12, 310 Estates Drive — 58-year-old female, fell, cannot get up, lying on floor since last night.", chief_complaint:"Ground-level fall, prolonged down time, rhabdomyolysis risk", scene_description:"Neighbor called after not seeing the woman for 24 hours. You find her on the bathroom floor alert but weak. She says she fell getting up to use the bathroom last night and has been on the floor approximately 12 hours. She cannot get herself up and is embarrassed.", patient_info:"58-year-old female, PMH: obesity, Type 2 diabetes, hypertension. Takes metformin, lisinopril.", vitals:{bp:"152/96",hr:"108",rr:"18",spo2:"96%",gcs:"15",temp:"99.4°F"}, pertinent_findings:"Right hip pain with external rotation of right lower extremity. Distal CSM intact. Skin pressure injury forming on right flank. Urine on floor suggesting inability to reach toilet. Patient is dehydrated with dry mucous membranes and dark urine visible.", teaching_points:"1. Prolonged immobility on a hard surface causes rhabdomyolysis — muscle breakdown releases myoglobin into the bloodstream which can cause acute kidney failure; communicate the extended downtime precisely to the ER as early IV fluid resuscitation is critical. 2. Assess for and document pressure injuries from the floor — even 12 hours on a hard surface can cause significant tissue damage especially in a diabetic patient; document any skin breakdown for the receiving facility." },
  { dispatch_line:"Medic 12, 45 Big Daddy Estates Blvd — 16-year-old male, friend called 911, unresponsive, possible overdose, parents not home.", chief_complaint:"Teenage opioid overdose, altered mental status, respiratory depression", scene_description:"You arrive to a residential home. A 16-year-old's friend called 911 saying he took something. The homeowner is not present. The teen is on the couch responding minimally. Several empty beer cans and an empty prescription bottle with someone else's name are on the coffee table.", patient_info:"16-year-old male, PMH: unknown. Prescription bottle on scene — oxycodone 10mg, 30 count, now empty.", vitals:{bp:"96/58",hr:"56",rr:"8",spo2:"88%",gcs:"7",temp:"97.4°F"}, pertinent_findings:"Respiratory depression with SpO2 88% and RR 8. Bradycardic. Pinpoint pupils bilaterally. GCS 7 — responds to sternal rub only. Empty oxycodone bottle on scene. Alcohol also consumed based on empty cans and odor.", teaching_points:"1. Opioid toxidrome — pinpoint pupils, respiratory depression, and decreased level of consciousness confirms opioid overdose; BVM ventilation is your first intervention when SpO2 is 88%; support ventilation while preparing naloxone per protocol. 2. Naloxone in a teenager is the same clinical situation as in an adult — administer per your protocol; be prepared for agitation after reversal especially with concurrent alcohol ingestion." },
],

bd_hospital: [
  { dispatch_line:"Medic 12, Big Daddy Regional — routine IFT, 68-year-old male, transfer to Grand-daddy's Nursing and Rehab after knee replacement, stable.", chief_complaint:"Routine transfer to rehab — patient develops chest pain en route", scene_description:"You are transporting a 68-year-old male to Grand-daddy's Nursing and Rehab after an uncomplicated knee replacement. He is alert, in good spirits, and comfortable when you leave the hospital. Twelve minutes into transport he tells you his chest hurts. He describes it as pressure, not sharp, and says it started a few minutes ago. He looks pale.", patient_info:"68-year-old male, PMH: hypertension, hyperlipidemia, smoker x20 years. Recent knee replacement POD#2.", vitals:{bp:"158/96",hr:"102",rr:"20",spo2:"94%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"New substernal chest pressure rated 6/10 onset during transport. Pale and mildly diaphoretic. SpO2 94% on room air. Tachycardic. No aspirin given — not listed on discharge paperwork. Patient has no known aspirin allergy.", teaching_points:"1. New chest pain during an IFT is a cardiac emergency — this is no longer a routine transfer; notify dispatch immediately, apply O2 to maintain SpO2 above 94%, administer aspirin 324mg PO if not contraindicated, and divert to the nearest ER; do not continue to the rehab facility. 2. Document the exact time of symptom onset during transport — time of symptom onset directly affects ER decision-making for cardiac intervention; your documentation of when the pain started in transit is critical clinical information." },
  { dispatch_line:"Medic 12, Big Daddy Regional — routine IFT, 72-year-old female, transfer to primary care physician office for follow-up appointment.", chief_complaint:"Routine doctor appointment transfer — patient becomes confused and acting strangely en route", scene_description:"You are transporting a 72-year-old female diabetic to her primary care doctor for a routine follow-up after a hospitalization for pneumonia. She was alert and conversational when you loaded her. About 15 minutes into the 20-minute transport she stops responding normally, seems confused about where she is, and is staring blankly. Her answers don't make sense.", patient_info:"72-year-old female, PMH: Type 2 diabetes on insulin, hypertension, recent pneumonia hospitalization. Takes insulin glargine and metformin.", vitals:{bp:"108/66",hr:"112",rr:"18",spo2:"98%",gcs:"13",temp:"98.4°F"}, pertinent_findings:"Acute onset confusion and altered behavior during transport. Diaphoretic and pale. Tachycardic. BG by glucometer reads 48 mg/dL — hypoglycemia. She has not eaten since last night per family. Insulin was given this morning.", teaching_points:"1. Any acute change in mental status during transport requires an immediate assessment — always check blood glucose in a diabetic patient with altered mental status; a BG of 48 confirms hypoglycemia as the cause; if the patient can swallow and protect her airway, oral glucose is your first-line treatment at the EMT level. 2. Reassess blood glucose and mental status 15 minutes after oral glucose — if the patient does not improve or cannot maintain her airway, transport back to the hospital rather than continuing to the doctor's office; a confused diabetic cannot safely receive outpatient care." },
  { dispatch_line:"Medic 12, Big Daddy Regional — home discharge transport, 77-year-old male, hip replacement, being transferred from stretcher to recliner at home.", chief_complaint:"Patient falls during transfer from stretcher to recliner, ankle deformity", scene_description:"You are completing a home discharge for a 77-year-old male after hip replacement. The patient is alert and cooperative. While transferring him from your stretcher to his recliner, his foot catches on the footrest and he twists his right ankle with a pop. He immediately cries out in pain and cannot move his foot. Significant swelling is forming rapidly.", patient_info:"77-year-old male, PMH: osteoporosis, hypertension, recent hip replacement. Takes lisinopril and a daily aspirin.", vitals:{bp:"162/94",hr:"108",rr:"18",spo2:"98%",gcs:"15",temp:"98.6°F"}, pertinent_findings:"Right ankle deformity with immediate swelling and ecchymosis following a twisting mechanism. Patient rates pain 8/10. Distal CSM intact — able to wiggle toes with pain. Cannot bear weight. Mechanism and osteoporosis increase fracture likelihood.", teaching_points:"1. Document the incident thoroughly and objectively — a patient injury during your care requires precise documentation of exactly what happened, the mechanism, and your assessment findings; this protects both you and the patient and is required for your agency's incident reporting. 2. Splint the ankle in position found using a padded board or pillow splint — assess and document CSM before and after splinting; this patient needs transport back to the ER for imaging; do not leave him at home with an unassessed ankle deformity." },
  { dispatch_line:"Medic 12, Big Daddy Regional — IFT, 66-year-old male, transfer to County General for outpatient procedure, stable at pickup.", chief_complaint:"Routine IFT — patient develops shortness of breath, becomes shocky en route", scene_description:"You are transporting a 66-year-old male to County General for an outpatient procedure. He had a hip surgery one week ago and has been on bedrest. Ten minutes into transport he becomes suddenly short of breath and anxious. He says he feels like something is wrong. His skin becomes pale, cool, and clammy rapidly. He is deteriorating in front of you.", patient_info:"66-year-old male, PMH: hypertension, recent hip surgery one week ago, prolonged bedrest. Takes lisinopril.", vitals:{bp:"88/56",hr:"128",rr:"28",spo2:"88%",gcs:"14",temp:"98.4°F"}, pertinent_findings:"Sudden onset shortness of breath with rapid deterioration to shock — hypotensive, tachycardic, tachypneic. SpO2 88%. Pale, cool, diaphoretic skin. Recent surgery with prolonged immobility — high risk for pulmonary embolism. Obstructive shock physiology.", teaching_points:"1. Treat for shock immediately — high-flow O2 via NRB mask, position of comfort (sitting up is better tolerated in respiratory distress), keep the patient warm with a blanket to prevent heat loss, notify dispatch of your change in patient condition, and divert to the nearest ER; this patient cannot continue to County General. 2. Pulmonary embolism presents with sudden shortness of breath, tachycardia, hypotension, and low SpO2 in a patient with recent surgery and immobility — obstructive shock from a massive PE is rapidly fatal without hospital intervention; your only interventions are oxygen, shock treatment, and rapid transport." },
],

bd_gasgo: [
  { dispatch_line:"Medic 12, Big Daddy's Gas and Go — male found unresponsive in the restroom, suspected overdose, naloxone needed.", chief_complaint:"Opioid OD, respiratory failure, confined space", scene_description:"The gas station clerk called 911 after a male had been in the single stall bathroom for over 30 minutes. He was found on the floor with a used syringe beside him. He has a faint pulse and barely perceptible respirations. The tight bathroom space limits your ability to work.", patient_info:"Approximately 35-year-old male, PMH: unknown. Track marks both forearms.", vitals:{bp:"86/52",hr:"52",rr:"4 agonal",spo2:"72%",gcs:"3",temp:"96.8°F"}, pertinent_findings:"Agonal respirations with SpO2 72%. Pinpoint pupils bilaterally. Bradycardic. GCS 3. Cyanotic lips and fingertips. Single stall bathroom limits patient access and BVM effectiveness.", teaching_points:"1. Scene management in a small bathroom requires patient relocation — you cannot effectively manage an airway or perform CPR in a single stall bathroom; move the patient to the hallway or parking lot before beginning treatment. 2. Naloxone via IN route allows immediate administration without IV access — 2mg IN while simultaneously moving the patient and positioning the airway; always ventilate with BVM while waiting for naloxone effect." },
  { dispatch_line:"Medic 12, Big Daddy's Gas and Go — female, 64-year-old, collapsed at the gas pump, bystander CPR in progress.", chief_complaint:"Witnessed cardiac arrest, bystander CPR, AED on scene", scene_description:"A female collapsed while pumping gas. A bystander immediately started CPR. An AED is on the wall inside the station. You arrive 4 minutes after the call. CPR is ongoing with good technique. A crowd has gathered.", patient_info:"64-year-old female, PMH: unknown per bystanders.", vitals:{bp:"pulseless",hr:"pulseless",rr:"apneic",spo2:"not obtainable",gcs:"3",temp:"unknown"}, pertinent_findings:"Pulseless and apneic. Bystander CPR ongoing with good quality. AED available inside the store. Estimated downtime 4 minutes with continuous CPR. Pavement surface.", teaching_points:"1. Hard flat surfaces like pavement improve CPR quality — compression depth and recoil are more effective on hard surfaces than on mattresses or soft ground; do not move the patient off pavement unless there is a safety reason. 2. Get the AED on the patient immediately — every minute without defibrillation reduces survival by 7-10%; one crew member retrieves the AED while another maintains compressions; minimize hands-off time to under 10 seconds for rhythm analysis." },
  { dispatch_line:"Medic 12, Big Daddy's Gas and Go — male, 44-year-old, MVC into canopy, diabetic medical alert bracelet, BG 24.", chief_complaint:"MVC caused by hypoglycemia, BG 24, airway assessment", scene_description:"A male driver appears to have had a medical episode and drove into the canopy support column. He is conscious but confused. Significant front-end damage with airbag deployment. Fire department en route. His medical alert bracelet reads Diabetic — Insulin Dependent. BG is 24 mg/dL.", patient_info:"44-year-old male, PMH: Type 1 DM on insulin. Medical alert bracelet confirmed.", vitals:{bp:"102/64",hr:"128",rr:"22",spo2:"96%",gcs:"13",temp:"98.6°F"}, pertinent_findings:"BG 24 mg/dL — critically low, hypoglycemia caused the crash. Confused and combative from neuroglycopenia. Airbag deployed. Chest wall tenderness. Cervical spine precautions applied. Medical alert bracelet identified the etiology.", teaching_points:"1. Medical alert bracelets change your assessment — always check for medical alert jewelry in any trauma or altered mental status patient; this patient's BG of 24 confirms hypoglycemia caused the crash, not driver inattention; treat the medical cause as aggressively as the trauma. 2. Confirm scene safety with fire department before approaching a vehicle into structure — risk of structural collapse, fuel leak, or electrical hazard; do not approach until the scene is declared safe." },
  { dispatch_line:"Medic 12, Big Daddy's Gas and Go — 17-year-old female, syncopal episode inside the store, 14 weeks pregnant.", chief_complaint:"Syncope, pregnancy 14 weeks, dehydration and heat exposure", scene_description:"A 17-year-old female collapsed inside the convenience store. She was unconscious for about 20 seconds and is now alert and embarrassed. She has not eaten since yesterday and has been in the heat for several hours. She discloses she is 14 weeks pregnant with no prenatal care established.", patient_info:"17-year-old female, PMH: none. 14 weeks pregnant, no prenatal care.", vitals:{bp:"92/58",hr:"106",rr:"16",spo2:"99%",gcs:"15",temp:"99.0°F"}, pertinent_findings:"Syncopal episode in early second trimester pregnancy. Mildly tachycardic and hypotensive. No prenatal care established. She is alone and does not want to call her parents. Dehydration and heat exposure are the likely precipitants.", teaching_points:"1. Transport all pregnant patients who have syncopal episodes — even if she appears fully recovered, ectopic pregnancy, placental abruption, and other OB emergencies can present as syncope; she needs OB evaluation and ultrasound confirmation of intrauterine pregnancy. 2. A pregnant minor can typically consent to her own medical care — in most states pregnancy grants a minor the right to consent for obstetric-related care; document her consent, her pregnancy status, and that she was transported to an OB-capable facility." },
],

};